INSERT INTO datasets (name, layer, cartridge, sources, sql_def, description, column_mapping, schedule, updated_at)
VALUES ($seed$consultor_asignacion$seed$, $seed$gold$seed$, $seed$replicon$seed$, $seed$["raw/replicon/ResourceAllocation"]$seed$::jsonb, $seed$WITH

-- 1. Asignacion como espina (todos los meses, incluyendo futuro)
alloc AS (
    SELECT
        DATE_TRUNC('month', CAST(date AS DATE))                AS mes,
        username,
        projectcode,
        SUM(durationhours)                                     AS horas_asignadas
    FROM (
        SELECT *, ROW_NUMBER() OVER (
            PARTITION BY date, userid, projectid
            ORDER BY load_date DESC
        ) AS rn
        FROM read_parquet('s3://{bucket}/raw/replicon/ResourceAllocation/**/*.parquet')
    ) WHERE rn = 1
    GROUP BY 1, 2, 3
),

-- 2. Empleados: supervisor, departamento
empleados AS (
    SELECT
        LOWER(TRIM(usuario))                                    AS usuario_key,
        TRIM(usuario)                                           AS consultor,
        COALESCE(NULLIF(TRIM(supervisor), ''), 'N/D')          AS supervisor,
        COALESCE(NULLIF(TRIM(departamento), ''), 'N/D')        AS departamento,
        COALESCE(tipo_empleado, 'Unknown')                     AS tipo_empleado
    FROM read_parquet('s3://{bucket}/silver/replicon/empleados_maestro/data.parquet')
),

-- 3. Revenue manager por proyecto
proj_rm AS (
    SELECT project_code, project_name, revenue_manager FROM (
        SELECT
            "Project Code"                                      AS project_code,
            "Project Name"                                      AS project_name,
            COALESCE(NULLIF(TRIM("Revenue Manager"), ''), 'N/D') AS revenue_manager,
            ROW_NUMBER() OVER (
                PARTITION BY "Project Code"
                ORDER BY "FechaReporte" DESC NULLS LAST
            ) AS rn
        FROM read_parquet('s3://{bucket}/silver/replicon/replicon_project_detail_curated/data.parquet')
    ) WHERE rn = 1
),

-- 4. Horas ejecutadas desde TimeEntry (solo meses con registros)
te_agg AS (
    SELECT
        DATE_TRUNC('month', TRY_CAST(entrydate AS DATE))       AS mes,
        username,
        projectcode,
        SUM(durationhours)                                     AS horas_ejecutadas,
        SUM(CASE WHEN isbillable THEN durationhours ELSE 0 END) AS horas_facturables,
        SUM(CASE WHEN NOT isbillable THEN durationhours ELSE 0 END) AS horas_no_facturables
    FROM read_parquet('s3://{bucket}/silver/replicon/replicon_timeentry_latest/data.parquet')
    WHERE entrydate IS NOT NULL
    GROUP BY 1, 2, 3
)

SELECT
    al.mes,
    COALESCE(NULLIF(em.supervisor,'N/D'), pr.revenue_manager, 'N/D') AS revenue_manager,
    COALESCE(em.supervisor, 'N/D')                                 AS supervisor,
    COALESCE(em.departamento, 'N/D')                               AS departamento,
    COALESCE(em.consultor, al.username)                            AS consultor,
    COALESCE(em.tipo_empleado, 'Unknown')                          AS tipo_empleado,
    al.projectcode                                                 AS proyecto,
    COALESCE(pr.project_name, '')                                  AS project_name,
    ROUND(al.horas_asignadas, 2)                                   AS horas_asignadas,
    ROUND(COALESCE(te.horas_ejecutadas, 0), 2)                    AS horas_ejecutadas,
    ROUND(COALESCE(te.horas_facturables, 0), 2)                   AS horas_facturables,
    ROUND(COALESCE(te.horas_no_facturables, 0), 2)                AS horas_no_facturables,
    ROUND(al.horas_asignadas / 168.0 * 100, 1)                    AS pct_asignacion,
    ROUND(COALESCE(te.horas_ejecutadas, 0) / 168.0 * 100, 1)     AS pct_ejecucion,
    CASE WHEN COALESCE(te.horas_ejecutadas, 0) = 0 THEN 'futuro'
         ELSE 'ejecutado' END                                      AS estado
FROM alloc al
LEFT JOIN empleados em
    ON em.usuario_key = LOWER(TRIM(al.username))
LEFT JOIN proj_rm pr
    ON pr.project_code = al.projectcode
LEFT JOIN te_agg te
    ON te.username = al.username
    AND te.projectcode = al.projectcode
    AND te.mes = al.mes$seed$, $seed$Asignación mensual por consultor y proyecto, incluyendo meses futuros. Espina desde ResourceAllocation raw. Horas ejecutadas unidas cuando existen en TimeEntry. Permite vista de horizonte de capacidad completo.$seed$, $seed${}$seed$::jsonb, NULL, NOW())
ON CONFLICT (name) DO NOTHING;

INSERT INTO datasets (name, layer, cartridge, sources, sql_def, description, column_mapping, schedule, updated_at)
VALUES ($seed$consultor_mensual$seed$, $seed$gold$seed$, $seed$replicon$seed$, $seed$["raw/replicon/TimeEntry"]$seed$::jsonb, $seed$WITH

-- 1. Catálogo de empleados: supervisor, depto, costo/hora
empleados AS (
    SELECT
        LOWER(TRIM(usuario))                                    AS usuario_key,
        TRIM(usuario)                                           AS consultor,
        COALESCE(NULLIF(TRIM(supervisor), ''), 'N/D')          AS supervisor,
        COALESCE(NULLIF(TRIM(departamento), ''), 'N/D')        AS departamento,
        COALESCE(tipo_empleado, 'Unknown')                     AS tipo_empleado,
        COALESCE(costo_hora, 0)                                AS costo_hora
    FROM read_parquet('s3://{bucket}/silver/replicon/empleados_maestro/data.parquet')
),

-- 2. Horas asignadas por usuario+proyecto+mes (raw ResourceAllocation, deduplicado por load_date)
alloc_raw AS (
    SELECT
        DATE_TRUNC('month', CAST(date AS DATE))                AS mes,
        username,
        projectcode,
        SUM(durationhours)                                     AS horas_asignadas
    FROM (
        SELECT *, ROW_NUMBER() OVER (
            PARTITION BY date, userid, projectid
            ORDER BY load_date DESC
        ) AS rn
        FROM read_parquet('s3://{bucket}/raw/replicon/ResourceAllocation/**/*.parquet')
    ) WHERE rn = 1
    GROUP BY 1, 2, 3
),

-- 3. Tarifa de facturación por usuario+proyecto
billing_rates AS (
    SELECT userid, projectcode, billing_rate_usd
    FROM read_parquet('s3://{bucket}/silver/replicon/replicon_resourceallocation_latest/data.parquet')
),

-- 3. Revenue manager por proyecto (más reciente)
proj_rm AS (
    SELECT project_code, project_name, revenue_manager FROM (
        SELECT
            "Project Code"                                      AS project_code,
            "Project Name"                                      AS project_name,
            COALESCE(NULLIF(TRIM("Revenue Manager"), ''), 'N/D') AS revenue_manager,
            ROW_NUMBER() OVER (
                PARTITION BY "Project Code"
                ORDER BY "FechaReporte" DESC NULLS LAST
            ) AS rn
        FROM read_parquet('s3://{bucket}/silver/replicon/replicon_project_detail_curated/data.parquet')
    ) WHERE rn = 1
),

-- 4. BillingItem: revenue pre-calculado por Replicon (fallback cuando billing_rate=0)
billing_items AS (
    SELECT
        DATE_TRUNC('month', CAST(entrydate AS DATE))            AS mes,
        username,
        projectcode,
        SUM(COALESCE(billableamountbasecurrency, 0))           AS revenue_bi
    FROM read_parquet('s3://{bucket}/silver/replicon/replicon_billingitem_latest/data.parquet')
    WHERE isbillable = true AND entrydate IS NOT NULL
    GROUP BY 1, 2, 3
),

-- 5. TimeEntry enriquecido con tarifa y costo por hora
te AS (
    SELECT
        DATE_TRUNC('month', TRY_CAST(te.entrydate AS DATE))    AS mes,
        te.username,
        te.userid,
        te.projectcode,
        te.clientname,
        te.durationhours,
        te.isbillable,
        COALESCE(br.billing_rate_usd, 0)                       AS billing_rate_usd,
        COALESCE(em.costo_hora, 0)                             AS costo_hora,
        COALESCE(em.supervisor, 'N/D')                         AS supervisor,
        COALESCE(em.departamento, 'N/D')                       AS departamento,
        COALESCE(em.tipo_empleado, 'Unknown')                  AS tipo_empleado,
        COALESCE(em.consultor, te.username)                    AS consultor_nombre
    FROM read_parquet('s3://{bucket}/silver/replicon/replicon_timeentry_latest/data.parquet') te
    LEFT JOIN billing_rates br
        ON br.userid = te.userid AND br.projectcode = te.projectcode
    LEFT JOIN empleados em
        ON em.usuario_key = LOWER(TRIM(te.username))
),

-- 6a. Costo hundido a nivel empleado/mes
--     Solo Employees: MAX(0, 168 - horas_totales) × costo/hora
--     Ocioso puro: tiempo no registrado. costo_no_facturable se suma aparte sin duplicar.
hundido_emp AS (
    SELECT
        username, mes, costo_hora,
        SUM(CASE WHEN isbillable THEN durationhours ELSE 0 END) AS hrs_fact_total,
        SUM(durationhours)                                      AS hrs_total,
        GREATEST(0, 168.0 - SUM(durationhours))
            * costo_hora                                        AS costo_hundido
    FROM te
    WHERE mes IS NOT NULL
      AND tipo_empleado = 'Employee'
      AND costo_hora > 0
    GROUP BY username, mes, costo_hora
),

-- 6b. Peso de horas facturables por consultor+proyecto+mes
fact_pesos AS (
    SELECT
        username, mes, projectcode,
        SUM(CASE WHEN isbillable THEN durationhours ELSE 0 END) AS hrs_fact
    FROM te
    WHERE mes IS NOT NULL
    GROUP BY username, mes, projectcode
),

-- 6c. Costo hundido prorrateado a cada proyecto
hundido_proj AS (
    SELECT
        fp.mes, fp.username, fp.projectcode,
        SUM(fp.hrs_fact / NULLIF(he.hrs_fact_total, 0)
            * he.costo_hundido)                                AS costo_hundido
    FROM fact_pesos fp
    JOIN hundido_emp he
        ON he.username = fp.username AND he.mes = fp.mes
    GROUP BY fp.mes, fp.username, fp.projectcode
),

-- 7. Agregación principal: consultor + proyecto + mes
te_agg AS (
    SELECT
        mes,
        username,
        MAX(consultor_nombre)                                  AS consultor_v,
        MAX(supervisor)                                        AS supervisor_v,
        MAX(departamento)                                      AS departamento_v,
        MAX(tipo_empleado)                                     AS tipo_empleado_v,
        projectcode,
        MAX(clientname)                                        AS cliente,
        MAX(billing_rate_usd)                                  AS billing_rate_usd,
        MAX(costo_hora)                                        AS costo_hora,
        SUM(durationhours)                                     AS horas_ejecutadas,
        SUM(CASE WHEN isbillable  THEN durationhours ELSE 0 END) AS horas_facturables,
        SUM(CASE WHEN NOT isbillable THEN durationhours ELSE 0 END) AS horas_no_facturables,
        SUM(CASE WHEN isbillable  THEN durationhours * billing_rate_usd ELSE 0 END) AS revenue_tarifa,
        SUM(CASE WHEN isbillable  THEN durationhours * costo_hora ELSE 0 END) AS costo_directo,
        SUM(CASE WHEN NOT isbillable THEN durationhours * costo_hora ELSE 0 END) AS costo_no_facturable
    FROM te
    WHERE mes IS NOT NULL
    GROUP BY mes, username, projectcode
)

SELECT
    ta.mes,
    COALESCE(NULLIF(ta.supervisor_v,'N/D'), pr.revenue_manager, 'N/D') AS revenue_manager,
    ta.departamento_v  AS departamento,
    ta.consultor_v     AS consultor,
    ta.tipo_empleado_v AS tipo_empleado,
    ta.projectcode                                             AS proyecto,
    COALESCE(pr.project_name, '')                              AS project_name,
    ta.cliente,
    ROUND(COALESCE(al.horas_asignadas, 0), 2)                  AS horas_asignadas,
    ROUND(ta.horas_ejecutadas, 2)                              AS horas_ejecutadas,
    ROUND(ta.horas_facturables, 2)                             AS horas_facturables,
    ROUND(ta.horas_no_facturables, 2)                          AS horas_no_facturables,
    ROUND(GREATEST(0, 168.0 - ta.horas_ejecutadas), 2)        AS horas_hundidas_capacidad,
    ta.billing_rate_usd,
    ta.costo_hora,
    ROUND(ta.costo_directo, 2)                                 AS costo_directo,
    ROUND(ta.costo_no_facturable, 2)                           AS costo_no_facturable,
    ROUND(COALESCE(hp.costo_hundido, 0), 2)                   AS costo_hundido,
    ROUND(ta.costo_directo
          + ta.costo_no_facturable
          + COALESCE(hp.costo_hundido, 0), 2)                 AS costo_total,
    ROUND(CASE
        WHEN ta.revenue_tarifa > 0 THEN ta.revenue_tarifa
        ELSE COALESCE(bi.revenue_bi, 0)
    END, 2)                                                    AS revenue_generado
FROM te_agg ta
LEFT JOIN hundido_proj hp
    ON hp.username = ta.username AND hp.projectcode = ta.projectcode AND hp.mes = ta.mes
LEFT JOIN proj_rm pr
    ON pr.project_code = ta.projectcode
LEFT JOIN billing_items bi
    ON bi.username = ta.username AND bi.projectcode = ta.projectcode AND bi.mes = ta.mes
LEFT JOIN alloc_raw al
    ON al.username = ta.username AND al.projectcode = ta.projectcode AND al.mes = ta.mes$seed$, $seed$Métricas mensuales por consultor y proyecto. Revenue Manager = supervisor del consultor (empleados_maestro), fallback a revenue_manager del proyecto. Horas ejecutadas, facturables, no facturables. Costos directo, no facturable y hundido prorrateado.$seed$, $seed${}$seed$::jsonb, NULL, NOW())
ON CONFLICT (name) DO NOTHING;

INSERT INTO datasets (name, layer, cartridge, sources, sql_def, description, column_mapping, schedule, updated_at)
VALUES ($seed$costo_consultor_mensual$seed$, $seed$gold$seed$, $seed$replicon$seed$, $seed$["raw/replicon/TimeEntry"]$seed$::jsonb, $seed$WITH te AS (
    SELECT userid, username,
        
        DATE_TRUNC('month', CAST(entrydate AS DATE)) AS mes,
        SUM(durationhours) AS horas_ejecutadas
    FROM read_parquet('s3://{bucket}/silver/replicon/replicon_timeentry_latest/data.parquet')
    GROUP BY userid, username, DATE_TRUNC('year', CAST(entrydate AS DATE)),DATE_TRUNC('month', CAST(entrydate AS DATE))
),
u AS (
    SELECT userid,
        CONCAT(firstname, ' ', lastname) AS nombre_completo,
        departmentname AS departamento,
        currenthourlycostamount AS rate_costo
    FROM read_parquet('s3://{bucket}/silver/replicon/replicon_user_latest/data.parquet')
),
horas_mes AS (
    SELECT mes,
        ROUND(EXTRACT(DAY FROM (mes + INTERVAL '1 month' - INTERVAL '1 day'))::INT * 5.0 / 7.0 * 8, 2) AS horas_disponibles
    FROM (SELECT DISTINCT mes FROM te)
)
SELECT
   
   te.mes,
    te.userid,
    u.nombre_completo,
    te.username,
    u.departamento,
    u.rate_costo,
    hm.horas_disponibles,
    ROUND(te.horas_ejecutadas, 2)                                                     AS horas_ejecutadas,
    GREATEST(ROUND(hm.horas_disponibles - te.horas_ejecutadas, 2), 0)                AS horas_hundidas,
    ROUND(te.horas_ejecutadas * u.rate_costo, 2)                                     AS costo_ejecutado,
    ROUND(GREATEST(hm.horas_disponibles - te.horas_ejecutadas, 0) * u.rate_costo, 2) AS costo_hundido,
    ROUND(hm.horas_disponibles * u.rate_costo, 2)                                    AS costo_potencial_mes
FROM te
JOIN u  ON u.userid = te.userid
JOIN horas_mes hm ON hm.mes = te.mes
ORDER BY te.mes DESC, u.nombre_completo$seed$, $seed$Costo mensual por consultor: ejecutado (horas×rate) y hundido (horas disponibles - ejecutadas)×rate$seed$, $seed${}$seed$::jsonb, NULL, NOW())
ON CONFLICT (name) DO NOTHING;

INSERT INTO datasets (name, layer, cartridge, sources, sql_def, description, column_mapping, schedule, updated_at)
VALUES ($seed$pnl_mensual$seed$, $seed$gold$seed$, $seed$replicon$seed$, $seed$["raw/replicon/ResourceAllocation"]$seed$::jsonb, $seed$WITH

-- 1. Catalogo proyectos: tipo, revenue manager (project_detail_curated deduplicado)
proj_catalog AS (
    SELECT project_code, project_name, revenue_manager, project_type, pct_avance_real FROM (
        SELECT
            "Project Code"                                                   AS project_code,
            "Project Name"                                                   AS project_name,
            COALESCE(NULLIF(TRIM("Revenue Manager"), ''), 'N/D')            AS revenue_manager,
            "Project Type"                                                   AS project_type,
            COALESCE("% Real Progress", 0)                                   AS pct_avance_real,
            ROW_NUMBER() OVER (PARTITION BY "Project Code" ORDER BY "FechaReporte" DESC NULLS LAST) AS rn
        FROM read_parquet('s3://{bucket}/silver/replicon/replicon_project_detail_curated/data.parquet')
    ) WHERE rn = 1
),

-- 2. Valor de contrato (FPP revenue base) desde project_latest
--    projectcurrencyid=1 → USD, projectcurrencyid=8 → MXN (÷20)
proj_contract AS (
    SELECT project_code, cliente, valor_contrato FROM (
        SELECT
            code                                                             AS project_code,
            clientname                                                       AS cliente,
            CASE WHEN projectcurrencyid = 8
                 THEN COALESCE(totalestimatedcontractamount, 0) / 20.0
                 ELSE COALESCE(totalestimatedcontractamount, 0)
            END                                                              AS valor_contrato,
            ROW_NUMBER() OVER (PARTITION BY code ORDER BY load_date DESC NULLS LAST) AS rn
        FROM read_parquet('s3://{bucket}/silver/replicon/replicon_project_latest/data.parquet')
    ) WHERE rn = 1
),

-- 3. Tarifas de facturacion por usuario+proyecto (T&M, AMS On Demand)
billing_rates AS (
    SELECT userid, projectcode, billing_rate_usd
    FROM read_parquet('s3://{bucket}/silver/replicon/replicon_resourceallocation_latest/data.parquet')
),

-- 4. Revenue T&M desde BillingItem (fallback cuando billing_rate_usd = 0)
--    billableamountbasecurrency ya viene calculado por Replicon (horas × tarifa real)
billing_items AS (
    SELECT
        DATE_TRUNC('month', CAST(entrydate AS DATE))                        AS mes,
        projectcode,
        SUM(COALESCE(billableamountbasecurrency, 0))                       AS revenue_usd
    FROM read_parquet('s3://{bucket}/silver/replicon/replicon_billingitem_latest/data.parquet')
    WHERE isbillable = true AND entrydate IS NOT NULL
    GROUP BY 1, 2
),

-- 5. Revenue FPP: suma de incrementos de avance x valor_contrato por mes
fpp_revenue AS (
    SELECT
        DATE_TRUNC('month', CAST(ph.modified_at AS DATE))                  AS mes,
        ph.project_code,
        SUM(GREATEST(ph.real_progress_increment, 0) / 100.0
            * COALESCE(pc.valor_contrato, 0))                              AS revenue_usd
    FROM read_parquet('s3://{bucket}/silver/replicon/project_progress_history/data.parquet') ph
    LEFT JOIN proj_contract pc ON pc.project_code = ph.project_code
    GROUP BY 1, 2
),

-- 5. Facturacion en USD por proyecto/mes
--    Project Code en billing viene como float string ("29630595633.0") — normalizar a entero
facturacion AS (
    SELECT
        DATE_TRUNC('month', CAST("Fecha" AS DATE))                         AS mes,
        CAST(TRY_CAST(TRY_CAST("Project Code" AS DOUBLE) AS BIGINT) AS VARCHAR) AS project_code,
        SUM(CASE WHEN "Moneda" = 'MXN' THEN "Subtotal" / 20.0
                 ELSE "Subtotal" END)                                      AS facturacion_mes_usd
    FROM read_parquet('s3://{bucket}/silver/replicon/replicon_projectbilling_curated/data.parquet')
    WHERE "Fecha" IS NOT NULL AND "Project Code" != '0'
    GROUP BY 1, 2
),

-- 6. TimeEntry enriquecido: tarifa facturacion y costo/hora por usuario+proyecto
te_enriched AS (
    SELECT
        te.username,
        te.projectcode,
        te.clientname,
        DATE_TRUNC('month', TRY_CAST(te.entrydate AS DATE))                AS mes,
        te.durationhours,
        te.isbillable,
        COALESCE(br.billing_rate_usd, 0)                                   AS billing_rate_usd,
        COALESCE(em.costo_hora, 0)                                         AS costo_hora,
        COALESCE(em.tipo_empleado, 'Unknown')                              AS tipo_empleado
    FROM read_parquet('s3://{bucket}/silver/replicon/replicon_timeentry_latest/data.parquet') te
    LEFT JOIN billing_rates br
        ON br.userid = te.userid AND br.projectcode = te.projectcode
    LEFT JOIN read_parquet('s3://{bucket}/silver/replicon/empleados_maestro/data.parquet') em
        ON LOWER(TRIM(em.usuario)) = LOWER(TRIM(te.username))
),

-- 7a. Costo hundido por empleado/mes:
--     MAX(0, 168 - horas_totales_registradas) × costo/hora
--     Ocioso puro: tiempo no registrado. costo_no_facturable no se duplica.
--     Solo Employees (no Contractors). Mínimo 0.
hundido_empleado AS (
    SELECT
        username,
        mes,
        costo_hora,
        SUM(CASE WHEN isbillable THEN durationhours ELSE 0 END)            AS hrs_fact_total,
        GREATEST(0, 168.0
            - SUM(durationhours))
            * costo_hora                                                    AS costo_hundido
    FROM te_enriched
    WHERE mes IS NOT NULL AND tipo_empleado = 'Employee' AND costo_hora > 0
    GROUP BY username, mes, costo_hora
),

-- 7b. Horas facturables por empleado+proyecto+mes (pesos del prorrateo)
fact_pesos AS (
    SELECT
        username,
        mes,
        projectcode,
        SUM(durationhours)                                                  AS hrs_fact
    FROM te_enriched
    WHERE isbillable = true AND mes IS NOT NULL
    GROUP BY username, mes, projectcode
),

-- 7c. Costo hundido prorrateado a cada proyecto según peso de horas facturables
hundido_prorateado AS (
    SELECT
        fp.mes,
        fp.projectcode,
        SUM(fp.hrs_fact / NULLIF(he.hrs_fact_total, 0)
            * he.costo_hundido)                                            AS costo_hundido
    FROM fact_pesos fp
    JOIN hundido_empleado he
        ON he.username = fp.username AND he.mes = fp.mes
    GROUP BY fp.mes, fp.projectcode
),

-- 7. Métricas de tiempo por proyecto/mes (sin costo_hundido — viene de hundido_prorateado)
te_agg AS (
    SELECT
        mes,
        projectcode                                                         AS project_code,
        MAX(clientname)                                                     AS cliente_te,
        SUM(CASE WHEN isbillable THEN durationhours ELSE 0 END)            AS horas_facturables,
        SUM(durationhours)                                                  AS horas_totales,
        SUM(CASE WHEN isbillable
                 THEN durationhours * billing_rate_usd ELSE 0 END)         AS revenue_tarifa,
        SUM(CASE WHEN isbillable
                 THEN durationhours * costo_hora ELSE 0 END)               AS costo_directo
    FROM te_enriched
    WHERE mes IS NOT NULL
    GROUP BY mes, project_code
),

-- 8. P&L base con revenue por tipo de proyecto
pnl_base AS (
    SELECT
        ta.mes,
        COALESCE(pc.revenue_manager, 'N/D')                                AS revenue_manager,
        COALESCE(pc2.cliente, ta.cliente_te, 'N/D')                        AS cliente,
        ta.project_code                                                     AS proyecto,
        COALESCE(pc.project_name, '')                                      AS project_name,
        COALESCE(pc.project_type, 'N/D')                                   AS tipo_proyecto,
        COALESCE(pc.pct_avance_real, 0)                                    AS pct_avance_real,
        CASE
            WHEN pc.project_type = 'FPP'
                THEN COALESCE(fr.revenue_usd, 0)
            WHEN pc.project_type IN ('T&M', 'AMS (On Demand)')
                THEN CASE
                    WHEN ta.revenue_tarifa > 0 THEN ta.revenue_tarifa
                    ELSE COALESCE(bi.revenue_usd, 0)   -- fallback: BillingItem cuando tarifa no está en ResourceAllocation
                END
            WHEN pc.project_type IN ('AMS (Base Line)', 'BPO', 'CFDI-Timbrado')
                THEN COALESCE(fac.facturacion_mes_usd, 0)
            ELSE CASE
                    WHEN ta.revenue_tarifa > 0 THEN ta.revenue_tarifa
                    ELSE COALESCE(bi.revenue_usd, 0)
                END
        END                                                                 AS revenue_usd,
        COALESCE(fac.facturacion_mes_usd, 0)                               AS facturacion_mes_usd,
        ta.costo_directo,
        COALESCE(hp.costo_hundido, 0)                                      AS costo_hundido,
        ta.costo_directo + COALESCE(hp.costo_hundido, 0)                   AS costo_total,
        ta.horas_facturables,
        ta.horas_totales
    FROM te_agg ta
    LEFT JOIN proj_catalog pc   ON pc.project_code  = ta.project_code
    LEFT JOIN proj_contract pc2 ON pc2.project_code = ta.project_code
    LEFT JOIN fpp_revenue fr    ON fr.project_code  = ta.project_code AND fr.mes = ta.mes
    LEFT JOIN facturacion fac   ON fac.project_code = ta.project_code AND fac.mes = ta.mes
    LEFT JOIN billing_items bi  ON bi.projectcode   = ta.project_code AND bi.mes = ta.mes
    LEFT JOIN hundido_prorateado hp ON hp.projectcode = ta.project_code AND hp.mes = ta.mes
)

SELECT
    mes,
    revenue_manager,
    cliente,
    proyecto,
    project_name,
    tipo_proyecto,
    ROUND(revenue_usd, 2)                                                  AS revenue_usd,
    ROUND(facturacion_mes_usd, 2)                                          AS facturacion_mes_usd,
    ROUND(revenue_usd - facturacion_mes_usd, 2)                            AS wip_usd,
    ROUND(costo_directo, 2)                                                AS costo_directo,
    ROUND(costo_hundido, 2)                                                AS costo_hundido,
    ROUND(costo_total, 2)                                                  AS costo_total,
    ROUND(revenue_usd - costo_total, 2)                                    AS margen_bruto_usd,
    ROUND(
        CASE WHEN revenue_usd > 0
             THEN (revenue_usd - costo_total) / revenue_usd * 100
             ELSE NULL END, 2)                                             AS margen_bruto_pct,
    ROUND(horas_facturables, 2)                                            AS horas_facturables,
    ROUND(horas_totales, 2)                                                AS horas_totales,
    ROUND(pct_avance_real, 2)                                              AS pct_avance_real
FROM pnl_base
ORDER BY mes DESC, revenue_manager, cliente, proyecto$seed$, $seed$P&L mensual por Revenue Manager/Cliente/Proyecto. Revenue por tipo: FPP=avance*contrato, T&M/AMS On Demand=horas*tarifa, AMS Base Line/BPO=facturado. Costo en directo+hundido. WIP=revenue-facturacion.$seed$, $seed${}$seed$::jsonb, NULL, NOW())
ON CONFLICT (name) DO NOTHING;

