VALUES ($seed$empleados_maestro$seed$, $seed$master$seed$, $seed$replicon$seed$, $seed$["raw/replicon/User"]$seed$::jsonb, $seed$SELECT userid AS id_empleado, firstname AS nombre, lastname AS apellido, username AS usuario, email, currentsupervisorusername as supervisor, departmentname AS departamento, locationname AS ubicacion, employeetypename AS tipo_empleado, currenthourlycostamount AS costo_hora, currenthourlycostcurrencysymbol as costo_moneda, currenthourlybillingamount AS tarifa_facturacion FROM read_parquet('s3://{bucket}/raw/replicon/User/**/*.parquet', hive_partitioning=true, union_by_name=true) WHERE load_date = '2026-04-16' AND isenabled = true$seed$, $seed$Maestro de empleados activos con terminos de negocio$seed$, $seed${}$seed$::jsonb, NULL, NOW())
