<body>
    <div class="container">
        <div class="header">
            <h1>⚡ Gestión de Asignación y Utilización</h1>
            <p>Visualización en tiempo real de consultores asignados vs ejecutados</p>
        </div>

        <div class="filters-container">
            <div class="filter-title">🔍 Filtros</div>
            <div class="filter-group">
                <div class="filter-item">
                    <label for="fiscalPeriod">Período Fiscal (Marzo - Febrero)</label>
                    <select id="fiscalPeriod">
                        <option value="">Cargando...</option>
                    </select>
                </div>
                <div class="filter-item">
                    <label for="revenueManager">Revenue Manager</label>
                    <select id="revenueManager">
                        <option value="">Todos</option>
                    </select>
                </div>
                <div class="period-info">
                    <span id="periodInfo">Selecciona un período fiscal para ver los detalles</span>
                </div>
            </div>
        </div>

        <div class="kpi-grid" id="kpiGrid">
            <div class="loading">Cargando datos...</div>
        </div>

        <div class="charts-grid">
            <div class="chart-container">
                <div class="chart-title">📊 Asignación vs Ejecución (Período Seleccionado)</div>
                <canvas id="trendsChart"></canvas>
            </div>
            <div class="chart-container">
                <div class="chart-title">🎯 Distribución de Utilización por Consultor</div>
                <canvas id="distributionChart"></canvas>
            </div>
        </div>

        <div class="table-container">
            <div class="table-title">📋 Detalle por Consultor</div>
            <table id="dataTable">
                <thead>
                    <tr>
                        <th>Consultor</th>
                        <th>Departamento</th>
                        <th>Revenue Manager</th>
                        <th>Horas Asignadas</th>
                        <th>Horas Ejecutadas</th>
                        <th>Horas Facturables</th>
                        <th>% Asignación</th>
                        <th>% Ejecución</th>
                    </tr>
                </thead>
                <tbody id="tableBody"></tbody>
            </table>
        </div>
    </div>

    <script>
        let allData = [];
        let trendsChart = null;
        let distributionChart = null;

        // Función para calcular período fiscal (Marzo - Febrero)
        // Retorna: { start_year: 2024, label: "FY 2024-2025" }
        function getFiscalYearInfo(dateString) {
            const date = new Date(dateString);
            const year = date.getFullYear();
            const month = date.getMonth(); // 0=enero, 2=marzo, 11=diciembre
            
            // Si el mes es ENERO o FEBRERO (0, 1), pertenece al año fiscal anterior
            // Si el mes es MARZO a DICIEMBRE (2-11), es el año fiscal actual
            if (month <= 1) {
                // Enero, Febrero -> pertenece a FY del año anterior
                return {
                    start_year: year - 1,
                    label: `FY ${year - 1}-${year}`
                };
            } else {
                // Marzo a Diciembre -> pertenece a FY actual
                return {
                    start_year: year,
                    label: `FY ${year}-${year + 1}`
                };
            }
        }

        // Verifica si una fecha está dentro de un período fiscal
        function isInFiscalYear(dateString, fiscalStartYear) {
            const { start_year } = getFiscalYearInfo(dateString);
            return start_year === fiscalStartYear;
        }

        async function loadData() {
            try {
                const response = await fetch('/api/data/consultor_asignacion');
                const data = await response.json();
                
                if (!data || !Array.isArray(data)) {
                    console.error('Invalid data format');
                    return;
                }

                allData = data;
                populateFilters();
                applyFilters();
            } catch (error) {
                console.error('Error loading data:', error);
                document.getElementById('kpiGrid').innerHTML = '<div class="loading">Error cargando datos</div>';
            }
        }

        function populateFilters() {
            // Obtener períodos fiscales únicos
            const fiscalPeriods = new Set();
            const revenueManagers = new Set();

            allData.forEach(row => {
                const { start_year, label } = getFiscalYearInfo(row.mes);
                fiscalPeriods.add(JSON.stringify({ start_year, label }));
                if (row.revenue_manager && row.revenue_manager !== 'N/D') {
                    revenueManagers.add(row.revenue_manager);
                }
            });

            // Llenar select de períodos fiscales (ordenado descendente)
            const periodSelect = document.getElementById('fiscalPeriod');
            const periods = Array.from(fiscalPeriods)
                .map(p => JSON.parse(p))
                .sort((a, b) => b.start_year - a.start_year);
            
            periodSelect.innerHTML = '';
            periods.forEach(period => {
                const option = document.createElement('option');
                option.value = period.start_year;
                option.textContent = period.label;
                periodSelect.appendChild(option);
            });

            // Seleccionar el período más reciente por defecto
            if (periods.length > 0) {
                periodSelect.value = periods[0].start_year;
            }

            // Llenar select de Revenue Managers (ordenado)
            const rmSelect = document.getElementById('revenueManager');
            const baseOptions = rmSelect.innerHTML;
            const sortedRMs = Array.from(revenueManagers).sort();
            rmSelect.innerHTML = baseOptions;
            sortedRMs.forEach(rm => {
                const option = document.createElement('option');
                option.value = rm;
                option.textContent = rm;
                rmSelect.appendChild(option);
            });

            // Agregar event listeners
            periodSelect.addEventListener('change', applyFilters);
            rmSelect.addEventListener('change', applyFilters);
        }

        function applyFilters() {
            const selectedYear = parseInt(document.getElementById('fiscalPeriod').value);
            const selectedRM = document.getElementById('revenueManager').value;

            if (!selectedYear && selectedYear !== 0) {
                document.getElementById('kpiGrid').innerHTML = '<div class="loading">Selecciona un período fiscal</div>';
                return;
            }

            // Filtrar datos por período fiscal
            const filteredByPeriod = allData.filter(row => isInFiscalYear(row.mes, selectedYear));

            // Filtrar por Revenue Manager si está seleccionado
            const filtered = selectedRM 
                ? filteredByPeriod.filter(row => row.revenue_manager === selectedRM)
                : filteredByPeriod;

            // Actualizar período info
            const { label } = getFiscalYearInfo(`${selectedYear}-03-01`);
            document.getElementById('periodInfo').textContent = 
                `${label}` + 
                (selectedRM ? ` | Revenue Manager: ${selectedRM}` : '');

            processData(filtered);
        }

        function processData(data) {
            if (data.length === 0) {
                document.getElementById('kpiGrid').innerHTML = '<div class="loading">No hay datos para esta selección</div>';
                return;
            }

            // Agrupar por mes y consultor
            const monthlyData = {};
            const consultantData = {};
            
            data.forEach(row => {
                const month = row.mes.substring(0, 7); // YYYY-MM
                const consultant = row.consultor;
                
                if (!monthlyData[month]) monthlyData[month] = { asignadas: 0, ejecutadas: 0, facturables: 0 };
                if (!consultantData[consultant]) consultantData[consultant] = [];
                
                monthlyData[month].asignadas += row.horas_asignadas || 0;
                monthlyData[month].ejecutadas += row.horas_ejecutadas || 0;
                monthlyData[month].facturables += row.horas_facturables || 0;
                
                consultantData[consultant].push(row);
            });

            // KPIs
            const totalAsignadas = Object.values(monthlyData).reduce((s, m) => s + m.asignadas, 0);
            const totalEjecutadas = Object.values(monthlyData).reduce((s, m) => s + m.ejecutadas, 0);
            const totalFacturables = Object.values(monthlyData).reduce((s, m) => s + m.facturables, 0);
            const pctUtilization = totalAsignadas > 0 ? ((totalEjecutadas / totalAsignadas) * 100).toFixed(1) : 0;
            const pctFacturable = totalEjecutadas > 0 ? ((totalFacturables / totalEjecutadas) * 100).toFixed(1) : 0;
            const consultantCount = Object.keys(consultantData).length;

            renderKPIs(totalAsignadas, totalEjecutadas, totalFacturables, pctUtilization, pctFacturable, consultantCount);
            renderTrendsChart(monthlyData);
            renderDistributionChart(consultantData);
            renderTable(data);
        }

        function renderKPIs(asignadas, ejecutadas, facturables, pctUtil, pctFact, consultantCount) {
            const kpiGrid = document.getElementById('kpiGrid');
            kpiGrid.innerHTML = `
                <div class="kpi-card">
                    <div class="kpi-label">Total Asignadas</div>
                    <div class="kpi-value">${asignadas.toFixed(0)}</div>
                    <div class="kpi-subtext">horas</div>
                </div>
                <div class="kpi-card">
                    <div class="kpi-label">Total Ejecutadas</div>
                    <div class="kpi-value">${ejecutadas.toFixed(0)}</div>
                    <div class="kpi-subtext">horas registradas</div>
                </div>
                <div class="kpi-card">
                    <div class="kpi-label">% Utilización</div>
                    <div class="kpi-value">${pctUtil}%</div>
                    <div class="kpi-subtext">ejecutadas / asignadas</div>
                </div>
                <div class="kpi-card">
                    <div class="kpi-label">Total Facturables</div>
                    <div class="kpi-value">${facturables.toFixed(0)}</div>
                    <div class="kpi-subtext">horas billable</div>
                </div>
                <div class="kpi-card">
                    <div class="kpi-label">% Facturable</div>
                    <div class="kpi-value">${pctFact}%</div>
                    <div class="kpi-subtext">del total ejecutado</div>
                </div>
                <div class="kpi-card">
                    <div class="kpi-label">Consultores Activos</div>
                    <div class="kpi-value">${consultantCount}</div>
                    <div class="kpi-subtext">en período</div>
                </div>
            `;
        }

        function renderTrendsChart(monthlyData) {
            const months = Object.keys(monthlyData).sort();
            const asignadas = months.map(m => monthlyData[m].asignadas);
            const ejecutadas = months.map(m => monthlyData[m].ejecutadas);

            const ctx = document.getElementById('trendsChart').getContext('2d');
            
            if (trendsChart) trendsChart.destroy();
            
            trendsChart = new Chart(ctx, {
                type: 'line',
                data: {
                    labels: months,
                    datasets: [
                        {
                            label: 'Horas Asignadas',
                            data: asignadas,
                            borderColor: '#7c3aed',
                            backgroundColor: 'rgba(124, 58, 237, 0.1)',
                            tension: 0.4,
                            pointRadius: 5,
                            pointBackgroundColor: '#7c3aed',
                            pointBorderColor: '#fff',
                            pointBorderWidth: 2,
                            fill: true
                        },
                        {
                            label: 'Horas Ejecutadas',
                            data: ejecutadas,
                            borderColor: '#00d4ff',
                            backgroundColor: 'rgba(0, 212, 255, 0.1)',
                            tension: 0.4,
                            pointRadius: 5,
                            pointBackgroundColor: '#00d4ff',
                            pointBorderColor: '#fff',
                            pointBorderWidth: 2,
                            fill: true
                        }
                    ]
                },
                options: {
                    responsive: true,
                    maintainAspectRatio: true,
                    plugins: {
                        legend: { labels: { color: '#e0e0e0' } }
                    },
                    scales: {
                        y: { grid: { color: 'rgba(255,255,255,0.05)' }, ticks: { color: '#999' } },
                        x: { grid: { color: 'rgba(255,255,255,0.05)' }, ticks: { color: '#999' } }
                    }
                }
            });
        }

        function renderDistributionChart(consultantData) {
            const consultants = Object.keys(consultantData).sort();
            const utilizations = consultants.map(c => {
                const rows = consultantData[c];
                const assigned = rows.reduce((s, r) => s + (r.horas_asignadas || 0), 0);
                const executed = rows.reduce((s, r) => s + (r.horas_ejecutadas || 0), 0);
                return assigned > 0 ? (executed / assigned) * 100 : 0;
            });

            const colors = utilizations.map(u => {
                if (u >= 80) return '#22c55e';
                if (u >= 50) return '#eab308';
                return '#ef4444';
            });

            const ctx = document.getElementById('distributionChart').getContext('2d');
            
            if (distributionChart) distributionChart.destroy();
            
            distributionChart = new Chart(ctx, {
                type: 'bar',
                data: {
                    labels: consultants.map(c => c.substring(0, 18)),
                    datasets: [{
                        label: '% Utilización',
                        data: utilizations,
                        backgroundColor: colors,
                        borderColor: 'rgba(255,255,255,0.2)',
                        borderWidth: 1
                    }]
                },
                options: {
                    indexAxis: 'y',
                    responsive: true,
                    maintainAspectRatio: true,
                    plugins: {
                        legend: { labels: { color: '#e0e0e0' } }
                    },
                    scales: {
                        x: {
                            grid: { color: 'rgba(255,255,255,0.05)' },
                            ticks: { color: '#999' },
                            max: 150
                        },
                        y: { ticks: { color: '#999' } }
                    }
                }
            });
        }

        function renderTable(data) {
            const tbody = document.getElementById('tableBody');
            
            // Agrupar por consultor para agregar datos
            const byConsultant = {};
            data.forEach(row => {
                const key = row.consultor;
                if (!byConsultant[key]) {
                    byConsultant[key] = {
                        consultor: row.consultor,
                        departamento: row.departamento,
                        revenue_manager: row.revenue_manager,
                        horas_asignadas: 0,
                        horas_ejecutadas: 0,
                        horas_facturables: 0,
                        pct_asignacion: 0,
                        pct_ejecucion: 0
                    };
                }
                byConsultant[key].horas_asignadas += row.horas_asignadas || 0;
                byConsultant[key].horas_ejecutadas += row.horas_ejecutadas || 0;
                byConsultant[key].horas_facturables += row.horas_facturables || 0;
            });

            // Calcular porcentajes
            Object.values(byConsultant).forEach(row => {
                row.pct_asignacion = row.horas_asignadas > 0 ? (row.horas_asignadas / 168) * 100 : 0;
                row.pct_ejecucion = row.horas_asignadas > 0 ? (row.horas_ejecutadas / row.horas_asignadas) * 100 : 0;
            });

            // Ordenar por horas ejecutadas descendente
            const sorted = Object.values(byConsultant).sort((a, b) => b.horas_ejecutadas - a.horas_ejecutadas);

            tbody.innerHTML = sorted.slice(0, 50).map(row => `
                <tr>
                    <td><strong>${row.consultor}</strong></td>
                    <td>${row.departamento || 'N/D'}</td>
                    <td>${row.revenue_manager || 'N/D'}</td>
                    <td>${row.horas_asignadas.toFixed(1)}</td>
                    <td>${row.horas_ejecutadas.toFixed(1)}</td>
                    <td>${row.horas_facturables.toFixed(1)}</td>
                    <td><strong>${row.pct_asignacion.toFixed(1)}%</strong></td>
                    <td><strong>${row.pct_ejecucion.toFixed(1)}%</strong></td>
                </tr>
            `).join('');
        }

        // Load data on page load
        loadData();
    </script>
</body>
</html>$seed$, $seed$replicon$seed$, $seed$shared$seed$, NOW())
ON CONFLICT (name) DO NOTHING;

INSERT INTO analytic_apps (name, title, description, html, cartridge_id, visibility, updated_at)
VALUES ($seed$pnl_ejecutivo$seed$, $seed$P&L Ejecutivo$seed$, $seed$Vista ejecutiva del P&L por Revenue Manager. Tarjetas por proyecto con semáforo de salud (BUENO/ALERTA/CRÍTICO), KPIs grandes, alertas de riesgo y tendencia Revenue vs Facturación.$seed$, $seed$<!DOCTYPE html>
<html lang="es">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1">
<title>P&L Ejecutivo</title>
<script src="https://cdn.jsdelivr.net/npm/chart.js"></script>
<style>
:root{
  --bg:#0d1117;--bg2:#161b22;--bg3:#1e2736;--border:#30363d;
  --text1:#e6edf3;--text2:#8b949e;--text3:#58626d;
  --green:#2ea043;--green-glow:#39ff14;
  --blue:#7c9fff;--amber:#e3b341;--red:#f85149;
  --card-r:8px;
}
[data-theme=light]{
  --bg:#f0f2f5;--bg2:#ffffff;--bg3:#e8ecf1;--border:#d0d7de;
  --text1:#1f2328;--text2:#656d76;--text3:#a0aab4;
  --green:#1a7f37;--green-glow:#1a7f37;--blue:#0969da;--amber:#9a6700;--red:#cf222e;
}
*{box-sizing:border-box;margin:0;padding:0}
body{background:var(--bg);color:var(--text1);font-family:system-ui,-apple-system,sans-serif;min-height:100vh;transition:background .2s,color .2s}

/* ── Header ── */
.hdr{background:var(--bg2);border-bottom:1px solid var(--border);padding:16px 28px;display:flex;align-items:center;gap:16px}
.hdr-title{font-size:13px;font-weight:700;letter-spacing:1px;color:var(--blue);flex:1}
.hdr-sub{font-size:10px;color:var(--text2);letter-spacing:1px}
.theme-btn{background:transparent;border:1px solid var(--border);color:var(--text2);padding:5px 12px;font-size:10px;border-radius:20px;cursor:pointer}
.theme-btn:hover{border-color:var(--blue);color:var(--blue)}

/* ── Filters ── */
.filters{background:var(--bg2);border-bottom:1px solid var(--border);padding:12px 28px;display:flex;gap:12px;align-items:center;flex-wrap:wrap}
.filter-group{display:flex;align-items:center;gap:6px}
label{font-size:10px;color:var(--text2);white-space:nowrap;font-weight:600;letter-spacing:.5px}
/* ── Multi-select ── */
.ms-wrap{position:relative;min-width:180px}
.ms-trigger{background:var(--bg);border:1px solid var(--border);color:var(--text1);padding:7px 30px 7px 12px;font-size:11px;border-radius:6px;cursor:pointer;width:100%;text-align:left;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;display:block}
.ms-trigger:focus,.ms-trigger.open{outline:none;border-color:var(--blue)}
.ms-trigger::after{content:'▾';position:absolute;right:10px;top:50%;transform:translateY(-50%);color:var(--text2);font-size:10px;pointer-events:none}
.ms-dropdown{position:absolute;top:calc(100% + 4px);left:0;right:0;background:var(--bg2);border:1px solid var(--blue);border-radius:6px;z-index:999;max-height:240px;overflow-y:auto;box-shadow:0 8px 24px rgba(0,0,0,.4);display:none}
.ms-dropdown.open{display:block}
.ms-search{width:100%;background:var(--bg);border:none;border-bottom:1px solid var(--border);color:var(--text1);padding:8px 12px;font-size:10px;outline:none}
.ms-opt{display:flex;align-items:center;gap:8px;padding:7px 12px;cursor:pointer;font-size:10px}
.ms-opt:hover{background:var(--bg3)}
.ms-opt input[type=checkbox]{accent-color:var(--blue);width:12px;height:12px;flex-shrink:0}
.ms-actions{display:flex;gap:6px;padding:6px 10px;border-top:1px solid var(--border)}
.ms-action-btn{flex:1;background:transparent;border:1px solid var(--border);color:var(--text2);padding:4px;font-size:9px;border-radius:4px;cursor:pointer}
.ms-action-btn:hover{border-color:var(--blue);color:var(--blue)}
.btn{padding:8px 20px;font-size:11px;font-weight:600;border-radius:6px;cursor:pointer;border:none;letter-spacing:.5px}
.btn-primary{background:var(--blue);color:#fff}
.btn-primary:hover{opacity:.9}
.btn-primary:disabled{opacity:.4;cursor:not-allowed}
.spinner{display:inline-block;width:10px;height:10px;border:2px solid rgba(255,255,255,.3);border-top-color:#fff;border-radius:50%;animation:spin .6s linear infinite;vertical-align:middle;margin-right:6px}
@keyframes spin{to{transform:rotate(360deg)}}

/* ── Content ── */
.content{padding:24px 28px;max-width:1400px;margin:0 auto}

/* ── Placeholder ── */
.placeholder{text-align:center;padding:100px 20px;color:var(--text2)}
.placeholder-icon{font-size:40px;margin-bottom:16px;opacity:.3}
.placeholder h2{font-size:14px;font-weight:400;margin-bottom:8px;color:var(--text2)}
.placeholder p{font-size:11px;color:var(--text3)}

/* ── KPI strip ── */
.kpi-strip{display:grid;grid-template-columns:repeat(auto-fit,minmax(170px,1fr));gap:14px;margin-bottom:24px}
.kpi-card{background:var(--bg2);border:1px solid var(--border);border-radius:var(--card-r);padding:18px 20px;position:relative;overflow:hidden}
.kpi-card::before{content:'';position:absolute;top:0;left:0;width:3px;height:100%;background:var(--accent,var(--border))}
.kpi-label{font-size:9px;color:var(--text2);letter-spacing:1.5px;font-weight:600;margin-bottom:8px;text-transform:uppercase}
.kpi-val{font-size:22px;font-weight:700;color:var(--text1);line-height:1}
.kpi-sub{font-size:10px;color:var(--text3);margin-top:5px}
.kpi-badge{display:inline-block;padding:2px 8px;border-radius:10px;font-size:9px;font-weight:700;letter-spacing:.5px}
.badge-green{background:rgba(46,160,67,.15);color:var(--green)}
.badge-amber{background:rgba(227,179,65,.15);color:var(--amber)}
.badge-red{background:rgba(248,81,73,.15);color:var(--red)}
.badge-blue{background:rgba(124,159,255,.15);color:var(--blue)}

/* ── Alert banner ── */
.alert-banner{background:rgba(248,81,73,.08);border:1px solid rgba(248,81,73,.3);border-radius:var(--card-r);padding:14px 18px;margin-bottom:24px;display:flex;gap:12px;align-items:flex-start}
.alert-icon{font-size:16px;flex-shrink:0;margin-top:1px}
.alert-title{font-size:11px;font-weight:700;color:var(--red);margin-bottom:6px}
.alert-items{display:flex;flex-wrap:wrap;gap:6px}
.alert-chip{background:rgba(248,81,73,.12);border:1px solid rgba(248,81,73,.25);border-radius:4px;padding:3px 10px;font-size:10px;color:var(--red)}

/* ── Section ── */
.section{margin-bottom:28px}
.section-hdr{display:flex;align-items:baseline;gap:10px;margin-bottom:14px}
.section-title{font-size:11px;font-weight:700;letter-spacing:1px;color:var(--text2);text-transform:uppercase}
.section-count{font-size:10px;color:var(--text3)}

/* ── Project cards ── */
.proj-grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(320px,1fr));gap:14px}
.proj-card{background:var(--bg2);border:1px solid var(--border);border-radius:var(--card-r);padding:16px 18px;transition:border-color .15s}
.proj-card:hover{border-color:var(--blue)}
.proj-card-top{display:flex;justify-content:space-between;align-items:flex-start;margin-bottom:10px}
.proj-name{font-size:11px;font-weight:700;color:var(--text1);line-height:1.3;flex:1;margin-right:8px}
.proj-client{font-size:9px;color:var(--text2);margin-top:3px}
.proj-type{font-size:8px;color:var(--text3);letter-spacing:.5px;margin-top:2px}
.traffic-light{width:10px;height:10px;border-radius:50%;flex-shrink:0;margin-top:3px;box-shadow:0 0 6px var(--tl-color,transparent)}
.tl-green{background:var(--green);--tl-color:var(--green)}
.tl-amber{background:var(--amber);--tl-color:var(--amber)}
.tl-red{background:var(--red);--tl-color:var(--red)}
.tl-gray{background:var(--text3)}
.proj-metrics{display:grid;grid-template-columns:1fr 1fr 1fr;gap:8px;margin-bottom:10px}
.pm-item{text-align:center}
.pm-val{font-size:13px;font-weight:700;color:var(--text1)}
.pm-label{font-size:8px;color:var(--text3);letter-spacing:.5px;margin-top:2px}
.progress-wrap{margin-top:8px}
.progress-label{display:flex;justify-content:space-between;margin-bottom:4px}
.progress-label span{font-size:9px;color:var(--text2)}
.progress-bar{height:4px;background:var(--bg3);border-radius:2px;overflow:hidden}
.progress-fill{height:100%;border-radius:2px;transition:width .4s}
.fill-green{background:var(--green)}
.fill-amber{background:var(--amber)}
.fill-red{background:var(--red)}
.fill-blue{background:var(--blue)}

/* ── Trend chart ── */
.chart-card{background:var(--bg2);border:1px solid var(--border);border-radius:var(--card-r);padding:20px}
canvas{max-height:260px}

/* ── Summary table ── */
.tbl-wrap{overflow-x:auto;background:var(--bg2);border:1px solid var(--border);border-radius:var(--card-r)}
table{width:100%;border-collapse:collapse;font-size:10px}
th{padding:10px 14px;text-align:right;color:var(--text2);font-size:9px;letter-spacing:1px;border-bottom:1px solid var(--border);white-space:nowrap;font-weight:600}
th.left{text-align:left}
td{padding:9px 14px;text-align:right;border-bottom:1px solid var(--bg3);white-space:nowrap}
[data-theme=light] td{border-bottom:1px solid var(--bg3)}
td.left{text-align:left}
tr:last-child td{border-bottom:none}
tr:hover td{background:var(--bg3)}
.total-row td{border-top:2px solid var(--border);font-weight:700;color:var(--blue)}
.sort-btn{cursor:pointer;user-select:none}
.sort-btn:hover{color:var(--blue)}
.pos{color:var(--green)}.neg{color:var(--red)}.neu{color:var(--blue)}
</style>
</head>
<body>

<div class="hdr">
  <div>
    <div class="hdr-title">P&amp;L EJECUTIVO</div>
    <div class="hdr-sub">Visión por Revenue Manager &middot; Año Fiscal mar–feb</div>
  </div>
  <button class="theme-btn" id="theme-btn" onclick="toggleTheme()">☀ Claro</button>
</div>

<div class="filters">
  <div class="filter-group">
    <label>Revenue Manager</label>
    <div class="ms-wrap" id="ms-rm"></div>
  </div>
  <div class="filter-group">
    <label>Año Fiscal</label>
    <div class="ms-wrap" id="ms-yr"></div>
  </div>
  <div class="filter-group">
    <label>Cliente</label>
    <div class="ms-wrap" id="ms-cl"></div>
  </div>
  <button class="btn btn-primary" id="btn-filter" onclick="applyFilter()">Ver resultados</button>
</div>

<div class="content">

  <div id="placeholder" class="placeholder">
    <div class="placeholder-icon">📊</div>
    <h2>Selecciona un Revenue Manager y Año Fiscal</h2>
    <p>Presiona <strong>Ver resultados</strong> para cargar el portafolio</p>
  </div>

  <div id="main" style="display:none">

    <!-- KPIs -->
    <div class="kpi-strip" id="kpis"></div>

    <!-- Alertas -->
    <div id="alerts"></div>

    <!-- Tendencia -->
    <div class="section">
      <div class="section-hdr"><span class="section-title">Tendencia del período</span></div>
      <div class="chart-card"><canvas id="chart"></canvas></div>
    </div>

    <!-- Portfolio cards -->
    <div class="section">
      <div class="section-hdr">
        <span class="section-title">Portafolio de proyectos</span>
        <span class="section-count" id="proj-count"></span>
      </div>
      <div class="proj-grid" id="proj-grid"></div>
    </div>

    <!-- Tabla resumen -->
    <div class="section">
      <div class="section-hdr"><span class="section-title">Resumen consolidado</span></div>
      <div class="tbl-wrap" id="tbl-wrap"></div>
    </div>

  </div>
</div>

<script>
let ROWS = [];
let chartInst = null;
const PROJ_LABEL = {};

// ── Format helpers ──────────────────────────────────────────────────────────
const fmt  = n => n==null?'—':'$'+Number(n).toLocaleString('es-MX',{minimumFractionDigits:0,maximumFractionDigits:0});
const fmtD = n => n==null?'—':'$'+Number(n).toLocaleString('es-MX',{minimumFractionDigits:2,maximumFractionDigits:2});
const fmtH = n => n==null?'—':Number(n).toLocaleString('es-MX',{minimumFractionDigits:0,maximumFractionDigits:0})+' h';
const fmtP = n => n==null?'—':Number(n).toFixed(1)+'%';
const sign  = n => n>0?'+':'';

function fiscalYear(s){
  const p=(s||'').slice(0,7).split('-');
  const yr=parseInt(p[0])||0,mo=parseInt(p[1])||0;
  return mo<=2?yr-1:yr;
}
function groupBy(arr,key){return arr.reduce((m,r)=>{(m[r[key]]=m[r[key]]||[]).push(r);return m;},{});}
function sumRows(rows){
  const a={revenue_usd:0,facturacion_mes_usd:0,wip_usd:0,costo_directo:0,costo_hundido:0,costo_total:0,margen_bruto_usd:0,horas_facturables:0,horas_totales:0};
  rows.forEach(r=>Object.keys(a).forEach(k=>a[k]+=(+r[k]||0)));
  a.margen_bruto_pct=a.revenue_usd?(a.margen_bruto_usd/a.revenue_usd*100):null;
  return a;
}
function trafficClass(pct){
  if(pct==null) return 'tl-gray';
  if(pct>=20)   return 'tl-green';
  if(pct>=10)   return 'tl-amber';
  return 'tl-red';
}
function badgeClass(pct){
  if(pct==null) return 'badge-blue';
  if(pct>=20)   return 'badge-green';
  if(pct>=10)   return 'badge-amber';
  return 'badge-red';
}
function badgeLabel(pct){
  if(pct==null) return 'SIN REVENUE';
  if(pct>=20)   return '✓ BUENO';
  if(pct>=10)   return '⚠ ALERTA';
  return '✕ CRÍTICO';
}
function fillClass(pct){
  if(pct==null||pct<0) return 'fill-red';
  if(pct>=20) return 'fill-green';
  if(pct>=10) return 'fill-amber';
  return 'fill-red';
}

// ── Multi-select component ───────────────────────────────────────────────────
const MS = {};

function msCreate(containerId, placeholder='Todos'){
  const wrap=document.getElementById(containerId);
  wrap.innerHTML=`
    <button class="ms-trigger" onclick="msToggle('${containerId}',event)">${placeholder}</button>
    <div class="ms-dropdown" id="${containerId}-dd">
      <input class="ms-search" placeholder="Buscar…" oninput="msFilter('${containerId}',this.value)">
      <div id="${containerId}-list"></div>
      <div class="ms-actions">
        <button class="ms-action-btn" onclick="msAll('${containerId}',true)">Todo</button>
        <button class="ms-action-btn" onclick="msAll('${containerId}',false)">Ninguno</button>
      </div>
    </div>`;
  MS[containerId]={selected:new Set(),options:[],placeholder};
  document.addEventListener('click',e=>{
    if(!wrap.contains(e.target)) msClose(containerId);
  });
}

function msToggle(id,ev){
  if(ev) ev.stopPropagation();
  const dd=document.getElementById(id+'-dd');
  const btn=document.querySelector(`#${id} .ms-trigger`);
  const isOpen=dd.classList.contains('open');
  Object.keys(MS).forEach(k=>msClose(k));
  if(!isOpen){dd.classList.add('open');btn.classList.add('open');}
}
function msClose(id){
  document.getElementById(id+'-dd')?.classList.remove('open');
  document.querySelector(`#${id} .ms-trigger`)?.classList.remove('open');
}

function msSetOptions(id, options, labelFn=null){
  MS[id].options=options;
  msRender(id,'');
}

function msRender(id, search){
  const {options,selected}=MS[id];
  const filtered=search?options.filter(o=>String(o).toLowerCase().includes(search.toLowerCase())):options;
  document.getElementById(id+'-list').innerHTML=filtered.map(o=>`
    <label class="ms-opt">
      <input type="checkbox" value="${o}" ${selected.has(String(o))?'checked':''} onchange="msCheck('${id}','${String(o).replace(/'/g,"\\'")}',this.checked)">
      <span>${o}</span>
    </label>`).join('');
}

function msFilter(id,search){msRender(id,search);}

function msCheck(id,val,checked){
  if(checked) MS[id].selected.add(val); else MS[id].selected.delete(val);
  msUpdateLabel(id);
  if(id==='ms-rm'||id==='ms-yr'){clearTimeout(MS._t);MS._t=setTimeout(refreshClientes,400);}
}

function msAll(id,sel){
  const s=MS[id].selected;
  if(sel) MS[id].options.forEach(o=>s.add(String(o))); else s.clear();
  msRender(id,'');
  msUpdateLabel(id);
  if(id==='ms-rm'||id==='ms-yr'){clearTimeout(MS._t);MS._t=setTimeout(refreshClientes,400);}
}

function msUpdateLabel(id){
  const {selected,placeholder}=MS[id];
  const btn=document.querySelector(`#${id} .ms-trigger`);
  if(!selected.size) btn.textContent=placeholder;
  else if(selected.size===1) btn.textContent=[...selected][0];
  else btn.textContent=`${selected.size} seleccionados`;
}

function msGet(id){ return [...MS[id].selected]; }

// ── Selectors ───────────────────────────────────────────────────────────────
async function loadInitialOptions(){
  msCreate('ms-rm','Todos');
  msCreate('ms-yr','Selecciona…');
  msCreate('ms-cl','Todos');

  try{
    const r=await fetch('/api/data/pnl_mensual/options?columns=revenue_manager');
    const opts=await r.json();
    msSetOptions('ms-rm', opts.revenue_manager||[]);
  }catch(e){}

  try{
    const r=await fetch('/api/data/pnl_mensual/query',{
      method:'POST',headers:{'Content-Type':'application/json'},
      body:JSON.stringify({filters:{},limit:5000,columns:['mes']})
    });
    const rows=await r.json();
    if(Array.isArray(rows)){
      const fys=[...new Set(rows.map(r=>fiscalYear(r.mes)).filter(Boolean))].sort().reverse();
      msSetOptions('ms-yr', fys, y=>`AF${y} (mar ${y} – feb ${y+1})`);
      // override render to show custom labels
      const opts=fys;
      MS['ms-yr'].options=opts;
      document.getElementById('ms-yr-list').innerHTML=opts.map(y=>`
        <label class="ms-opt">
          <input type="checkbox" value="${y}" onchange="msCheck('ms-yr','${y}',this.checked)">
          <span>AF${y} &nbsp;<span style="color:var(--text3);font-size:9px">mar ${y} – feb ${y+1}</span></span>
        </label>`).join('');
    }
  }catch(e){}

  // Load clientes (all)
  try{
    const r=await fetch('/api/data/pnl_mensual/query',{
      method:'POST',headers:{'Content-Type':'application/json'},
      body:JSON.stringify({filters:{},limit:5000,columns:['cliente']})
    });
    const rows=await r.json();
    if(Array.isArray(rows)){
      const cls=[...new Set(rows.map(r=>r.cliente).filter(Boolean))].sort();
      msSetOptions('ms-cl', cls);
    }
  }catch(e){}
}

async function refreshClientes(){
  const rm=msGet('ms-rm'),yr=msGet('ms-yr').map(Number);
  const filters={};
  if(rm.length) filters.revenue_manager=rm.length===1?rm[0]:rm;
  if(yr.length) filters.fiscal_year=yr.length===1?yr[0]:yr;
  try{
    const r=await fetch('/api/data/pnl_mensual/query',{method:'POST',headers:{'Content-Type':'application/json'},
      body:JSON.stringify({filters,limit:5000,columns:['cliente']})});
    const rows=await r.json();
    if(!Array.isArray(rows)) return;
    const prevCl=msGet('ms-cl');
    const cls=[...new Set(rows.map(r=>r.cliente).filter(Boolean))].sort();
    msSetOptions('ms-cl',cls);
    prevCl.forEach(v=>{if(cls.includes(v))MS['ms-cl'].selected.add(v);}); msUpdateLabel('ms-cl');
  }catch(e){}
}

// ── Main query ──────────────────────────────────────────────────────────────
async function applyFilter(){
  const rm=msGet('ms-rm');
  const yr=msGet('ms-yr').map(Number);
  const cl=msGet('ms-cl');

  const filters={};
  if(rm.length) filters.revenue_manager=rm.length===1?rm[0]:rm;
  if(yr.length) filters.fiscal_year=yr.length===1?yr[0]:yr;
  if(cl.length) filters.cliente=cl.length===1?cl[0]:cl;

  const btn=document.getElementById('btn-filter');
  btn.innerHTML='<span class="spinner"></span>Cargando…';
  btn.disabled=true;

  try{
    const r=await fetch('/api/data/pnl_mensual/query',{
      method:'POST',headers:{'Content-Type':'application/json'},
      body:JSON.stringify({filters,limit:5000})
    });
    ROWS=await r.json();
    if(!Array.isArray(ROWS)) ROWS=[];
    ROWS.forEach(r=>{
      if(r.proyecto&&!PROJ_LABEL[r.proyecto])
        PROJ_LABEL[r.proyecto]=r.project_name?`${r.proyecto} — ${r.project_name}`:r.proyecto;
    });
    document.getElementById('placeholder').style.display='none';
    document.getElementById('main').style.display='';
    render();
  }catch(e){alert('Error: '+e.message);}
  finally{btn.textContent='Ver resultados';btn.disabled=false;}
}

// ── Render ──────────────────────────────────────────────────────────────────
function render(){
  renderKPIs(ROWS);
  renderAlerts(ROWS);
  renderChart(ROWS);
  renderProjGrid(ROWS);
  renderTable(ROWS);
}

function renderKPIs(rows){
  const t=sumRows(rows);
  const byProj=groupBy(rows,'proyecto');
  const nProj=Object.keys(byProj).length;
  const nRisk=Object.values(byProj).filter(rs=>{
    const s=sumRows(rs);
    return s.revenue_usd>0&&(s.margen_bruto_pct==null||s.margen_bruto_pct<10);
  }).length;

  const items=[
    {label:'Revenue Total',  val:fmt(t.revenue_usd),  sub:fmtD(t.revenue_usd)+' USD', accent:'var(--blue)',   klass:''},
    {label:'Facturado',      val:fmt(t.facturacion_mes_usd), sub:'Emitido en el período', accent:'var(--green)', klass:''},
    {label:'WIP',            val:fmt(t.wip_usd),       sub:'Revenue pendiente de facturar', accent:t.wip_usd>=0?'var(--amber)':'var(--red)', klass:''},
    {label:'Margen Bruto',   val:fmtP(t.margen_bruto_pct), sub:fmt(t.margen_bruto_usd)+' USD',
      accent:t.margen_bruto_pct>=20?'var(--green)':t.margen_bruto_pct>=10?'var(--amber)':'var(--red)', klass:''},
    {label:'Costo Directo',  val:fmt(t.costo_directo),  sub:'Horas facturables × tarifa', accent:'var(--text3)', klass:''},
    {label:'Costo Ocioso',   val:fmt(t.costo_hundido),  sub:'Capacidad no utilizada', accent:'var(--amber)', klass:''},
    {label:'Proyectos',      val:nProj,                sub:`${nRisk} en riesgo`, accent:'var(--blue)', klass:''},
    {label:'Horas Facturas', val:fmtH(t.horas_facturables), sub:'de '+fmtH(t.horas_totales)+' totales', accent:'var(--blue)', klass:''},
  ];
  document.getElementById('kpis').innerHTML=items.map(({label,val,sub,accent})=>`
    <div class="kpi-card" style="--accent:${accent}">
      <div class="kpi-label">${label}</div>
      <div class="kpi-val">${val}</div>
      <div class="kpi-sub">${sub}</div>
    </div>`).join('');
}

function renderAlerts(rows){
  const byProj=groupBy(rows,'proyecto');
  const risk=Object.entries(byProj)
    .map(([p,rs])=>({proj:p,t:sumRows(rs),r0:rs[0]}))
    .filter(({t})=>t.revenue_usd>0&&(t.margen_bruto_pct==null||t.margen_bruto_pct<10))
    .sort((a,b)=>a.t.margen_bruto_pct-b.t.margen_bruto_pct);

  const el=document.getElementById('alerts');
  if(!risk.length){el.innerHTML='';return;}

  el.innerHTML=`
    <div class="alert-banner">
      <div class="alert-icon">⚠</div>
      <div>
        <div class="alert-title">${risk.length} proyecto${risk.length>1?'s':''} con margen crítico (&lt; 10%)</div>
        <div class="alert-items">
          ${risk.map(({proj,t,r0})=>`
            <div class="alert-chip">${PROJ_LABEL[proj]||proj} · ${fmtP(t.margen_bruto_pct)}</div>
          `).join('')}
        </div>
      </div>
    </div>`;
}

function renderChart(rows){
  const byMes=groupBy(rows,'mes');
  const meses=Object.keys(byMes).sort();
  const revenue=meses.map(m=>sumRows(byMes[m]).revenue_usd);
  const factura=meses.map(m=>sumRows(byMes[m]).facturacion_mes_usd);
  const margen =meses.map(m=>sumRows(byMes[m]).margen_bruto_pct);
  const labels =meses.map(m=>{
    const p=m.slice(0,7).split('-');
    const mo=['','Ene','Feb','Mar','Abr','May','Jun','Jul','Ago','Sep','Oct','Nov','Dic'];
    return `${mo[parseInt(p[1])]} ${p[0].slice(2)}`;
  });

  if(chartInst) chartInst.destroy();
  const isLight=document.documentElement.dataset.theme==='light';
  const tick=isLight?'#656d76':'#8b949e';
  const grid=isLight?'#e8ecf0':'#1e2430';

  chartInst=new Chart(document.getElementById('chart').getContext('2d'),{
    data:{labels,datasets:[
      {type:'bar', label:'Revenue',     data:revenue, backgroundColor:'rgba(124,159,255,.6)',borderRadius:4,yAxisID:'y'},
      {type:'bar', label:'Facturado',   data:factura, backgroundColor:'rgba(46,160,67,.5)', borderRadius:4,yAxisID:'y'},
      {type:'line',label:'Margen %',    data:margen,  borderColor:isLight?'#e3a000':'#e3b341',
       backgroundColor:'transparent',tension:.3,pointRadius:4,borderWidth:2,yAxisID:'y2'},
    ]},
    options:{
      responsive:true,maintainAspectRatio:true,
      interaction:{mode:'index',intersect:false},
      plugins:{
        legend:{labels:{color:tick,font:{size:10},padding:16}},
        tooltip:{callbacks:{
          label:ctx=>{
            const ds=ctx.dataset.label;
            return ds==='Margen %'?` ${ds}: ${(ctx.raw||0).toFixed(1)}%`
              :` ${ds}: $${Number(ctx.raw||0).toLocaleString('es-MX',{maximumFractionDigits:0})}`;
          }
        }}
      },
      scales:{
        x:{ticks:{color:tick,font:{size:9}},grid:{color:grid}},
        y:{ticks:{color:tick,font:{size:9},callback:v=>'$'+Number(v/1000).toFixed(0)+'k'},grid:{color:grid},position:'left'},
        y2:{ticks:{color:isLight?'#9a6700':'#e3b341',font:{size:9},callback:v=>v+'%'},grid:{display:false},position:'right'},
      }
    }
  });
}

function renderProjGrid(rows){
  const byProj=groupBy(rows,'proyecto');
  const projs=Object.entries(byProj)
    .map(([p,rs])=>({proj:p,t:sumRows(rs),r0:rs[0],
      avance:rs.reduce((best,r)=>r.mes>(best.mes||'')?r:best,{}).pct_avance_real
    }))
    .sort((a,b)=>(b.t.revenue_usd)-(a.t.revenue_usd));

  document.getElementById('proj-count').textContent=`${projs.length} proyectos`;

  const maxRev=Math.max(...projs.map(p=>p.t.revenue_usd),1);

  document.getElementById('proj-grid').innerHTML=projs.map(({proj,t,r0,avance})=>{
    const pct=t.margen_bruto_pct;
    const tlClass=trafficClass(pct);
    const bgClass=badgeClass(pct);
    const bgLabel=badgeLabel(pct);
    const revPct=Math.min(100,(t.revenue_usd/maxRev)*100);
    const tipo=r0.tipo_proyecto||'';
    const isFPP=tipo==='FPP';
    const label=PROJ_LABEL[proj]||proj;

    return `
    <div class="proj-card">
      <div class="proj-card-top">
        <div>
          <div class="proj-name">${label}</div>
          <div class="proj-client">${r0.cliente||'—'}</div>
          <div class="proj-type">${tipo}</div>
        </div>
        <div class="traffic-light ${tlClass}" title="${bgLabel}"></div>
      </div>

      <div class="proj-metrics">
        <div class="pm-item">
          <div class="pm-val">${fmt(t.revenue_usd)}</div>
          <div class="pm-label">Revenue</div>
        </div>
        <div class="pm-item">
          <div class="pm-val ${pct>=20?'pos':pct>=10?'':pct!=null?'neg':''}">${fmtP(pct)}</div>
          <div class="pm-label">Margen</div>
        </div>
        <div class="pm-item">
          <div class="pm-val ${t.wip_usd>=0?'neu':'neg'}">${fmt(t.wip_usd)}</div>
          <div class="pm-label">WIP</div>
        </div>
      </div>

      <div class="progress-wrap">
        <div class="progress-label">
          <span>Revenue vs portafolio</span>
          <span>${Math.round(revPct)}%</span>
        </div>
        <div class="progress-bar">
          <div class="progress-fill fill-blue" style="width:${revPct}%"></div>
        </div>
      </div>

      ${isFPP&&avance!=null?`
      <div class="progress-wrap" style="margin-top:6px">
        <div class="progress-label">
          <span>Avance real</span>
          <span>${fmtP(avance)}</span>
        </div>
        <div class="progress-bar">
          <div class="progress-fill ${fillClass(avance)}" style="width:${Math.min(100,avance||0)}%"></div>
        </div>
      </div>`:''}

      <div style="margin-top:10px;display:flex;justify-content:space-between;align-items:center">
        <span class="kpi-badge ${bgClass}">${bgLabel}</span>
        <span style="font-size:9px;color:var(--text3)">${fmtH(t.horas_facturables)} fact.</span>
      </div>
    </div>`;
  }).join('');
}

function renderTable(rows){
  const byProj=groupBy(rows,'proyecto');
  const projs=Object.entries(byProj)
    .map(([p,rs])=>({proj:p,t:sumRows(rs),r0:rs[0]}))
    .sort((a,b)=>(b.t.revenue_usd)-(a.t.revenue_usd));
  const grand=sumRows(rows);

  const cols=[
    {key:'revenue_usd',     label:'Revenue',      f:fmt,  color:v=>v>0?'pos':v<0?'neg':''},
    {key:'facturacion_mes_usd',label:'Facturado', f:fmt,  color:()=>''},
    {key:'wip_usd',         label:'WIP',          f:fmt,  color:v=>v>=0?'neu':'neg'},
    {key:'costo_directo',   label:'C. Directo',   f:fmt,  color:()=>''},
    {key:'costo_hundido',   label:'C. Ocioso',    f:fmt,  color:()=>''},
    {key:'costo_total',     label:'Costo Total',  f:fmt,  color:()=>''},
    {key:'margen_bruto_usd',label:'Margen USD',   f:fmt,  color:v=>v>0?'pos':v<0?'neg':''},
    {key:'margen_bruto_pct',label:'Margen %',     f:fmtP, color:v=>v>=20?'pos':v>=10?'':v!=null?'neg':''},
  ];

  const head=`<tr>
    <th class="left">Proyecto</th>
    <th class="left">Cliente</th>
    <th class="left">Tipo</th>
    ${cols.map(c=>`<th>${c.label}</th>`).join('')}
  </tr>`;

  const body=projs.map(({proj,t,r0})=>`
    <tr>
      <td class="left" style="font-size:9px;max-width:200px;overflow:hidden;text-overflow:ellipsis">${PROJ_LABEL[proj]||proj}</td>
      <td class="left" style="font-size:9px;color:var(--text2)">${r0.cliente||'—'}</td>
      <td class="left" style="font-size:9px;color:var(--text3)">${r0.tipo_proyecto||'—'}</td>
      ${cols.map(c=>`<td class="${c.color(t[c.key])}">${c.f(t[c.key])}</td>`).join('')}
    </tr>`).join('');

  const totRow=`<tr class="total-row">
    <td class="left" colspan="3">TOTAL</td>
    ${cols.map(c=>`<td>${c.f(grand[c.key])}</td>`).join('')}
  </tr>`;

  document.getElementById('tbl-wrap').innerHTML=
    `<table><thead>${head}</thead><tbody>${body}${totRow}</tbody></table>`;
}

// ── Theme ────────────────────────────────────────────────────────────────────
function toggleTheme(){
  const html=document.documentElement;
  const isLight=html.dataset.theme==='light';
  html.dataset.theme=isLight?'dark':'light';
  document.getElementById('theme-btn').textContent=isLight?'☀ Claro':'☾ Oscuro';
  localStorage.setItem('pnl-exec-theme',html.dataset.theme);
  if(chartInst) renderChart(ROWS);
}

async function init(){
  const saved=localStorage.getItem('pnl-exec-theme')||'dark';
  document.documentElement.dataset.theme=saved;
  document.getElementById('theme-btn').textContent=saved==='light'?'☾ Oscuro':'☀ Claro';
  await loadInitialOptions();
}
init();
</script>
</body>
</html>$seed$, $seed$replicon$seed$, $seed$shared$seed$, NOW())
ON CONFLICT (name) DO NOTHING;

INSERT INTO analytic_apps (name, title, description, html, cartridge_id, visibility, updated_at)
VALUES ($seed$pnl_revenue_manager$seed$, $seed$P&L por Revenue Manager$seed$, $seed$Dashboard interactivo de P&L mensual. Consultas en tiempo real contra gold_pnl_mensual. Filtros por Revenue Manager, Año Fiscal (mar-feb), Cliente y Proyecto.$seed$, $seed$<!DOCTYPE html>
<html lang="es">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1">
<title>P&L por Revenue Manager</title>
<script src="https://cdn.jsdelivr.net/npm/chart.js"></script>
<style>
  :root{--bg:#0d1117;--bg2:#161b22;--border:#30363d;--text1:#e6edf3;--text2:#8b949e;--green:#39ff14;--blue:#7c9fff;--amber:#ffb300;--red:#f85149}
  [data-theme=light]{--bg:#f6f8fa;--bg2:#ffffff;--border:#d0d7de;--text1:#1f2328;--text2:#656d76;--green:#1a7f37;--blue:#0969da;--amber:#9a6700;--red:#cf222e}
  *{box-sizing:border-box;margin:0;padding:0}
  body{background:var(--bg);color:var(--text1);font-family:"Share Tech Mono",monospace,sans-serif;min-height:100vh;transition:background .2s,color .2s}
  h1{font-size:14px;letter-spacing:3px;color:var(--blue);padding:24px 28px 0}
  .subtitle{font-size:9px;color:var(--text2);letter-spacing:2px;padding:4px 28px 20px}
  .controls{padding:0 28px 20px;display:flex;gap:12px;align-items:center;flex-wrap:wrap}
  label{font-size:10px;color:var(--text2);white-space:nowrap}
  .ms-wrap{position:relative;min-width:160px}
  .ms-trigger{background:var(--bg2);border:1px solid var(--border);color:var(--text1);padding:6px 28px 6px 12px;font-size:11px;font-family:inherit;border-radius:4px;cursor:pointer;width:100%;text-align:left;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;display:block;position:relative}
  .ms-trigger::after{content:'▾';position:absolute;right:9px;top:50%;transform:translateY(-50%);color:var(--text2);font-size:10px;pointer-events:none}
  .ms-trigger.open,.ms-trigger:focus{outline:none;border-color:var(--blue)}
  .ms-dropdown{position:absolute;top:calc(100% + 3px);left:0;min-width:100%;background:var(--bg2);border:1px solid var(--blue);border-radius:4px;z-index:999;max-height:220px;overflow-y:auto;box-shadow:0 8px 24px rgba(0,0,0,.5);display:none}
  .ms-dropdown.open{display:block}
  .ms-search{width:100%;background:var(--bg);border:none;border-bottom:1px solid var(--border);color:var(--text1);padding:7px 10px;font-size:10px;font-family:inherit;outline:none}
  .ms-opt{display:flex;align-items:center;gap:7px;padding:6px 10px;cursor:pointer;font-size:10px;font-family:inherit}
  .ms-opt:hover{background:var(--bg)}
  .ms-opt input[type=checkbox]{accent-color:var(--blue);width:11px;height:11px;flex-shrink:0}
  .ms-actions{display:flex;gap:4px;padding:5px 8px;border-top:1px solid var(--border)}
  .ms-act{flex:1;background:transparent;border:1px solid var(--border);color:var(--text2);padding:3px;font-size:9px;font-family:inherit;border-radius:3px;cursor:pointer;letter-spacing:.5px}
  .ms-act:hover{border-color:var(--blue);color:var(--blue)}
  .btn-filter{background:var(--blue);border:none;color:#fff;padding:6px 18px;font-size:10px;font-family:inherit;border-radius:4px;cursor:pointer;letter-spacing:1px}
  .btn-filter:disabled{opacity:.5;cursor:not-allowed}
  .theme-btn{margin-left:auto;background:transparent;border:1px solid var(--border);color:var(--text2);padding:5px 12px;font-size:9px;font-family:inherit;border-radius:4px;cursor:pointer;letter-spacing:1px}
  .theme-btn:hover{border-color:var(--blue);color:var(--blue)}
  .kpis{display:flex;gap:14px;padding:0 28px 24px;flex-wrap:wrap}
  .kpi{background:var(--bg2);border:1px solid var(--border);border-radius:6px;padding:16px 20px;min-width:160px}
  .kpi-label{font-size:9px;color:var(--text2);letter-spacing:2px;margin-bottom:6px}
  .kpi-val{font-size:20px;color:var(--text1)}
  .kpi-val.pos{color:var(--green)}.kpi-val.neg{color:var(--red)}.kpi-val.neu{color:var(--blue)}
  .section{margin:0 28px 28px}
  .section-title{font-size:10px;letter-spacing:2px;color:var(--text2);border-bottom:1px solid var(--border);padding-bottom:8px;margin-bottom:14px}
  table{width:100%;border-collapse:collapse;font-size:10px}
  th{text-align:right;padding:7px 10px;color:var(--text2);font-size:9px;letter-spacing:1px;border-bottom:1px solid var(--border);white-space:nowrap}
  th.left{text-align:left}
  td{text-align:right;padding:6px 10px;border-bottom:1px solid #1e2430;white-space:nowrap}
  [data-theme=light] td{border-bottom:1px solid #e8ecf0}
  td.left{text-align:left;color:var(--text2)}
  tr:hover td{background:var(--bg2)}
  .pos-val{color:var(--green)}.neg-val{color:var(--red)}.neutral-val{color:var(--blue)}
  .placeholder{text-align:center;padding:80px 20px;color:var(--text2);font-size:11px;line-height:2.2}
  .spinner{display:inline-block;width:12px;height:12px;border:2px solid var(--border);border-top-color:var(--blue);border-radius:50%;animation:spin .7s linear infinite;vertical-align:middle;margin-right:6px}
  @keyframes spin{to{transform:rotate(360deg)}}
  .chart-wrap{background:var(--bg2);border:1px solid var(--border);border-radius:6px;padding:20px;margin-bottom:28px}
  canvas{max-height:280px}
  .row-count{font-size:9px;color:var(--text3);letter-spacing:1px;float:right;margin-top:-22px;padding-right:2px}
</style>
</head>
<body>
<h1>&#9638; P&amp;L POR REVENUE MANAGER</h1>
<div class="subtitle">CONSULTAS EN TIEMPO REAL &middot; GOLD TABLE pnl_mensual</div>

<div class="controls">
  <label>Revenue Manager:</label>
  <div class="ms-wrap" id="ms-rm"></div>
  <label>Año Fiscal:</label>
  <div class="ms-wrap" id="ms-yr"></div>
  <label>Cliente:</label>
  <div class="ms-wrap" id="ms-cl"></div>
  <label>Proyecto:</label>
  <div class="ms-wrap" id="ms-pr" style="min-width:200px"></div>
  <button class="btn-filter" id="btn-filter" onclick="applyFilter()">FILTRAR</button>
  <button class="theme-btn" id="theme-btn" onclick="toggleTheme()">☀ LIGHT</button>
</div>

<div id="placeholder" class="placeholder">
  Selecciona al menos un filtro y presiona <strong style="color:var(--blue)">FILTRAR</strong><br>
  <span style="font-size:9px;letter-spacing:1px">Año fiscal: marzo a febrero &mdash; AF2025 = mar-2025 a feb-2026</span>
</div>

<div id="main-content" style="display:none">
  <div id="kpis" class="kpis"></div>
  <div class="section">
    <div class="section-title">EVOLUCIÓN MENSUAL</div>
    <div class="chart-wrap"><canvas id="chart"></canvas></div>
  </div>
  <div class="section">
    <div class="section-title">RESUMEN POR MES</div>
    <div id="row-count-mes" class="row-count"></div>
    <div id="tbl-mes" style="overflow-x:auto"></div>
  </div>
  <div class="section">
    <div class="section-title">DESGLOSE POR PROYECTO</div>
    <div id="row-count-proj" class="row-count"></div>
    <div id="tbl-proj" style="overflow-x:auto"></div>
  </div>
</div>

<script>
let ROWS = [];
let chartInst = null;
const PROJ_LABEL = {};

const fmt  = n => n==null?'—':'$'+Number(n).toLocaleString('es-MX',{minimumFractionDigits:2,maximumFractionDigits:2});
const fmtH = n => n==null?'—':Number(n).toLocaleString('es-MX',{minimumFractionDigits:1,maximumFractionDigits:1})+' h';
const fmtP = n => n==null?'—':Number(n).toFixed(2)+'%';
const margColor = v => v==null?'':v>=20?'pos-val':v>=10?'neutral-val':'neg-val';
const kpiColor  = v => v==null?'':v>0?'pos':v<0?'neg':'neu';

function groupBy(arr,key){return arr.reduce((m,r)=>{(m[r[key]]=m[r[key]]||[]).push(r);return m;},{});}
function sumRows(rows){
  const a={revenue_usd:0,facturacion_mes_usd:0,wip_usd:0,costo_directo:0,costo_hundido:0,costo_total:0,margen_bruto_usd:0,horas_facturables:0,horas_totales:0};
  rows.forEach(r=>Object.keys(a).forEach(k=>a[k]+=(r[k]||0)));
  a.margen_bruto_pct=a.revenue_usd?(a.margen_bruto_usd/a.revenue_usd*100):null;
  return a;
}

// ── Multi-select component ──────────────────────────────────────────────────
const MS={};
function msCreate(id,ph='Todos'){
  const w=document.getElementById(id);
  w.innerHTML=`<button class="ms-trigger" onclick="msToggle('${id}',event)">${ph}</button>
    <div class="ms-dropdown" id="${id}-dd">
      <input class="ms-search" placeholder="Buscar…" oninput="msRender('${id}',this.value)">
      <div id="${id}-list"></div>
      <div class="ms-actions">
        <button class="ms-act" onclick="msAll('${id}',true)">TODO</button>
        <button class="ms-act" onclick="msAll('${id}',false)">NINGUNO</button>
      </div>
    </div>`;
  MS[id]={selected:new Set(),options:[],ph};
  document.addEventListener('click',e=>{if(!w.contains(e.target))msClose(id);});
}
function msToggle(id,ev){
  if(ev) ev.stopPropagation();
  const dd=document.getElementById(id+'-dd'),btn=document.querySelector(`#${id} .ms-trigger`);
  const was=dd.classList.contains('open');
  Object.keys(MS).forEach(k=>msClose(k));
  if(!was){dd.classList.add('open');btn.classList.add('open');}
}
function msClose(id){
  document.getElementById(id+'-dd')?.classList.remove('open');
  document.querySelector(`#${id} .ms-trigger`)?.classList.remove('open');
}
function msSetOptions(id,opts,labelFn=null){
  MS[id].options=opts; MS[id].labelFn=labelFn; msRender(id,'');
}
function msRender(id,search){
  const {options,selected,labelFn}=MS[id];
  const fil=search?options.filter(o=>String(labelFn?labelFn(o):o).toLowerCase().includes(search.toLowerCase())):options;
  document.getElementById(id+'-list').innerHTML=fil.map(o=>{
    const lbl=labelFn?labelFn(o):o;
    const val=String(o);
    return `<label class="ms-opt"><input type="checkbox" value="${val}" ${selected.has(val)?'checked':''} onchange="msCheck('${id}','${val.replace(/'/g,"\\'")}',this.checked)"><span>${lbl}</span></label>`;
  }).join('');
}
function msCheck(id,val,chk){chk?MS[id].selected.add(val):MS[id].selected.delete(val);msLabel(id);msCascade(id);}
function msAll(id,sel){
  const s=MS[id].selected;
  sel?MS[id].options.forEach(o=>s.add(String(o))):s.clear();
  msRender(id,''); msLabel(id); msCascade(id);
}
function msCascade(id){
  if(id==='ms-rm'||id==='ms-yr'){clearTimeout(MS._t);MS._t=setTimeout(refreshClientesProyectos,400);}
  if(id==='ms-cl'){clearTimeout(MS._t2);MS._t2=setTimeout(refreshProyectos,400);}
}
function msLabel(id){
  const {selected,ph,options,labelFn}=MS[id];
  const btn=document.querySelector(`#${id} .ms-trigger`);
  if(!selected.size) btn.textContent=ph;
  else if(selected.size===1) btn.textContent=labelFn?labelFn([...selected][0]):[...selected][0];
  else btn.textContent=`${selected.size} seleccionados`;
}
function msGet(id){return[...MS[id].selected];}

// ── Selectors ──────────────────────────────────────────────────────────────────

async function loadInitialOptions(){
  msCreate('ms-rm','Todos'); msCreate('ms-yr','Selecciona...'); msCreate('ms-cl','Todos'); msCreate('ms-pr','Todos');

  try{
    const r=await fetch('/api/data/pnl_mensual/options?columns=revenue_manager');
    const opts=await r.json();
    msSetOptions('ms-rm', opts.revenue_manager||[]);
  }catch(e){}

  try{
    const r=await fetch('/api/data/pnl_mensual/query',{
      method:'POST',headers:{'Content-Type':'application/json'},
      body:JSON.stringify({filters:{},limit:5000,columns:['mes']})
    });
    const rows=await r.json();
    if(Array.isArray(rows)){
      const fys=[...new Set(rows.map(r=>fiscalYear(r.mes)).filter(Boolean))].sort().reverse();
      msSetOptions('ms-yr', fys, y=>`AF${y} (mar-${y}/feb-${y+1})`);
    }
  }catch(e){}

  await refreshClientesProyectos();
}

async function refreshClientesProyectos(){
  const rm=msGet('ms-rm'), yr=msGet('ms-yr').map(Number);
  const filters={};
  if(rm.length) filters.revenue_manager=rm.length===1?rm[0]:rm;
  if(yr.length) filters.fiscal_year=yr.length===1?yr[0]:yr;
  try{
    const r=await fetch('/api/data/pnl_mensual/query',{
      method:'POST',headers:{'Content-Type':'application/json'},
      body:JSON.stringify({filters,limit:5000,columns:['cliente','proyecto','project_name']})
    });
    const rows=await r.json();
    if(!Array.isArray(rows)) return;
    rows.forEach(r=>{
      if(r.proyecto&&!PROJ_LABEL[r.proyecto])
        PROJ_LABEL[r.proyecto]=r.project_name?`${r.proyecto} — ${r.project_name}`:r.proyecto;
    });
    const cls=[...new Set(rows.map(r=>r.cliente).filter(Boolean))].sort();
    const prevCl=msGet('ms-cl'), prevPr=msGet('ms-pr');
    msSetOptions('ms-cl', cls);
    prevCl.forEach(v=>{if(cls.includes(v)) MS['ms-cl'].selected.add(v);}); msLabel('ms-cl');

    const clSel=msGet('ms-cl');
    const projRows=clSel.length?rows.filter(r=>clSel.includes(r.cliente)):rows;
    const prs=[...new Set(projRows.map(r=>r.proyecto).filter(Boolean))].sort();
    msSetOptions('ms-pr', prs, p=>PROJ_LABEL[p]||p);
    prevPr.forEach(v=>{if(prs.includes(v)) MS['ms-pr'].selected.add(v);}); msLabel('ms-pr');
  }catch(e){}
}

async function refreshProyectos(){
  const rm=msGet('ms-rm'),yr=msGet('ms-yr').map(Number),cl=msGet('ms-cl');
  const filters={};
  if(rm.length) filters.revenue_manager=rm.length===1?rm[0]:rm;
  if(yr.length) filters.fiscal_year=yr.length===1?yr[0]:yr;
  if(cl.length) filters.cliente=cl.length===1?cl[0]:cl;
  try{
    const r=await fetch('/api/data/pnl_mensual/query',{method:'POST',headers:{'Content-Type':'application/json'},
      body:JSON.stringify({filters,limit:5000,columns:['proyecto','project_name']})});
    const rows=await r.json();
    if(!Array.isArray(rows)) return;
    rows.forEach(r=>{if(r.proyecto&&!PROJ_LABEL[r.proyecto])PROJ_LABEL[r.proyecto]=r.project_name?`${r.proyecto} — ${r.project_name}`:r.proyecto;});
    const prevPr=msGet('ms-pr');
    const prs=[...new Set(rows.map(r=>r.proyecto).filter(Boolean))].sort();
    msSetOptions('ms-pr',prs,p=>PROJ_LABEL[p]||p);
    prevPr.forEach(v=>{if(prs.includes(v))MS['ms-pr'].selected.add(v);}); msLabel('ms-pr');
  }catch(e){}
}

// ── Main query ─────────────────────────────────────────────────────────────────

async function applyFilter(){
  const rm=msGet('ms-rm'), yr=msGet('ms-yr').map(Number), cl=msGet('ms-cl'), pr=msGet('ms-pr');
  const filters={};
  if(rm.length) filters.revenue_manager=rm.length===1?rm[0]:rm;
  if(yr.length) filters.fiscal_year=yr.length===1?yr[0]:yr;
  if(cl.length) filters.cliente=cl.length===1?cl[0]:cl;
  if(pr.length) filters.proyecto=pr.length===1?pr[0]:pr;

  const btn=document.getElementById('btn-filter');
  btn.innerHTML='<span class="spinner"></span>Consultando...';
  btn.disabled=true;

  try{
    const r=await fetch('/api/data/pnl_mensual/query',{
      method:'POST',headers:{'Content-Type':'application/json'},
      body:JSON.stringify({filters,limit:5000})
    });
    ROWS=await r.json();
    if(!Array.isArray(ROWS)) ROWS=[];
    ROWS.forEach(r=>{
      if(r.proyecto&&!PROJ_LABEL[r.proyecto])
        PROJ_LABEL[r.proyecto]=r.project_name?`${r.proyecto} — ${r.project_name}`:r.proyecto;
    });
    document.getElementById('placeholder').style.display='none';
    document.getElementById('main-content').style.display='';
    render();
  }catch(e){
    alert('Error: '+e.message);
  }finally{
    btn.textContent='FILTRAR'; btn.disabled=false;
  }
}

// ── Render ─────────────────────────────────────────────────────────────────────

function render(){
  renderKPIs(ROWS);
  renderChart(ROWS);
  renderTblMes(ROWS);
  renderTblProj(ROWS);
}

function renderKPIs(rows){
  const t=sumRows(rows);
  document.getElementById('kpis').innerHTML=[
    ['REVENUE',fmt(t.revenue_usd),kpiColor(t.revenue_usd)],
    ['FACTURACIÓN',fmt(t.facturacion_mes_usd),'neu'],
    ['WIP',fmt(t.wip_usd),kpiColor(t.wip_usd)],
    ['COSTO TOTAL',fmt(t.costo_total),''],
    ['MARGEN BRUTO',fmt(t.margen_bruto_usd),kpiColor(t.margen_bruto_usd)],
    ['MARGEN %',fmtP(t.margen_bruto_pct),margColor(t.margen_bruto_pct)],
    ['HRS FACTURABLES',fmtH(t.horas_facturables),'neu'],
  ].map(([l,v,c])=>`<div class="kpi"><div class="kpi-label">${l}</div><div class="kpi-val ${c}">${v}</div></div>`).join('');
}

function renderChart(rows){
  const byMes=groupBy(rows,'mes');
  const meses=Object.keys(byMes).sort();
  const revenue=meses.map(m=>sumRows(byMes[m]).revenue_usd);
  const costo=meses.map(m=>sumRows(byMes[m]).costo_total);
  const margen=meses.map(m=>sumRows(byMes[m]).margen_bruto_usd);
  const labels=meses.map(m=>m?m.slice(0,7):m);
  if(chartInst)chartInst.destroy();
  const isLight=document.documentElement.dataset.theme==='light';
  const tickColor=isLight?'#656d76':'#8b949e';
  const gridColor=isLight?'#d0d7de':'#1e2430';
  const margenColor=isLight?'#1a7f37':'#39ff14';
  const ctx=document.getElementById('chart').getContext('2d');
  chartInst=new Chart(ctx,{
    type:'bar',
    data:{labels,datasets:[
      {label:'Revenue',data:revenue,backgroundColor:'rgba(124,159,255,.7)',borderRadius:3},
      {label:'Costo Total',data:costo,backgroundColor:'rgba(248,81,73,.5)',borderRadius:3},
      {label:'Margen Bruto',data:margen,type:'line',borderColor:margenColor,
       backgroundColor:isLight?'rgba(26,127,55,.08)':'rgba(57,255,20,.08)',tension:.3,pointRadius:3,fill:true},
    ]},
    options:{
      responsive:true,maintainAspectRatio:true,
      plugins:{legend:{labels:{color:tickColor,font:{size:10}}}},
      scales:{
        x:{ticks:{color:tickColor,font:{size:9}},grid:{color:gridColor}},
        y:{ticks:{color:tickColor,font:{size:9},callback:v=>'$'+Number(v/1000).toFixed(0)+'k'},grid:{color:gridColor}}
      }
    }
  });
}

function renderTblMes(rows){
  const byMes=groupBy(rows,'mes');
  const meses=Object.keys(byMes).sort();
  const metrics=[
    ['revenue_usd',      'Revenue USD',   fmt,  v=>kpiColor(v)],
    ['costo_directo',    'Costo Directo', fmt,  ()=>''],
    ['costo_hundido',    'Costo Hundido', fmt,  ()=>''],
    ['costo_total',      'Costo Total',   fmt,  ()=>''],
    ['margen_bruto_usd', 'Margen Bruto',  fmt,  v=>kpiColor(v)],
    ['margen_bruto_pct', 'Margen %',      fmtP, v=>margColor(v)],
    ['facturacion_mes_usd','Facturación', fmt,  ()=>''],
    ['wip_usd',          'WIP',           fmt,  v=>kpiColor(v)],
  ];
  const totals=meses.reduce((m,mes)=>{m[mes]=sumRows(byMes[mes]);return m;},{});
  const grand=sumRows(rows);
  document.getElementById('row-count-mes').textContent=`${meses.length} meses`;
  const head='<tr><th class="left" style="min-width:130px">Métrica</th>'+
    meses.map(m=>`<th>${m.slice(0,7)}</th>`).join('')+
    '<th style="color:var(--blue)">Total</th></tr>';
  const body=metrics.map(([k,label,f,colorFn])=>{
    const cells=meses.map(mes=>{
      const v=totals[mes][k];
      return `<td class="${colorFn(v)}">${f(v)}</td>`;
    }).join('');
    const vT=grand[k];
    return `<tr><td class="left" style="color:var(--text2);font-size:9px;letter-spacing:1px">${label}</td>${cells}<td class="${colorFn(vT)}" style="font-weight:bold">${f(vT)}</td></tr>`;
  }).join('');
  document.getElementById('tbl-mes').innerHTML=`<table><thead>${head}</thead><tbody>${body}</tbody></table>`;
}

function renderTblProj(rows){
  const byProj=groupBy(rows,'proyecto');
  const projs=Object.keys(byProj).sort();
  const cols=[
    ['revenue_usd',       'Revenue',     fmt,  v=>kpiColor(v)],
    ['costo_directo',     'C.Directo',   fmt,  ()=>''],
    ['costo_hundido',     'C.Hundido',   fmt,  ()=>''],
    ['costo_total',       'C.Total',     fmt,  ()=>''],
    ['margen_bruto_usd',  'Margen USD',  fmt,  v=>kpiColor(v)],
    ['margen_bruto_pct',  'Margen %',    fmtP, v=>margColor(v)],
    ['facturacion_mes_usd','Facturación',fmt,  ()=>''],
    ['wip_usd',           'WIP',         fmt,  v=>kpiColor(v)],
    ['pct_avance_real',   '% Avance',    fmtP, ()=>''],
  ];
  document.getElementById('row-count-proj').textContent=`${projs.length} proyectos`;
  const head='<tr><th class="left">Proyecto</th><th class="left">Cliente</th><th class="left">Tipo</th>'+
    cols.map(([k,l])=>`<th>${l}</th>`).join('')+'</tr>';
  const body=projs.map(proj=>{
    const rs=byProj[proj];
    const t=sumRows(rs);
    const r0=rs[0];
    const avance=rs.reduce((best,r)=>r.mes>(best.mes||'')?r:best,{}).pct_avance_real;
    const label=PROJ_LABEL[proj]||proj;
    return '<tr>'+
      `<td class="left" style="font-size:9px">${label}</td>`+
      `<td class="left" style="font-size:9px">${r0.cliente||'—'}</td>`+
      `<td class="left" style="font-size:9px">${r0.tipo_proyecto||'—'}</td>`+
      cols.map(([k,l,f,colorFn])=>{
        const v=k==='pct_avance_real'?avance:t[k];
        return `<td class="${colorFn(v)}">${f(v)}</td>`;
      }).join('')+'</tr>';
  }).join('');
  const grand=sumRows(rows);
  const totRow='<tr style="border-top:2px solid var(--blue);font-weight:bold">'+
    '<td class="left" style="font-size:9px;color:var(--blue)">TOTAL</td>'+
    '<td class="left"></td><td class="left"></td>'+
    cols.map(([k,l,f,colorFn])=>{
      if(k==='pct_avance_real') return '<td>—</td>';
      const v=grand[k];
      return `<td class="${colorFn(v)}">${f(v)}</td>`;
    }).join('')+'</tr>';
  document.getElementById('tbl-proj').innerHTML=`<table><thead>${head}</thead><tbody>${body}${totRow}</tbody></table>`;
}

// ── Theme ──────────────────────────────────────────────────────────────────────

function toggleTheme(){
  const html=document.documentElement;
  const isDark=html.dataset.theme!=='light';
  html.dataset.theme=isDark?'light':'dark';
  document.getElementById('theme-btn').textContent=isDark?'☾ DARK':'☀ LIGHT';
  localStorage.setItem('pnl-theme',html.dataset.theme);
  if(chartInst) renderChart(ROWS);
}

function fiscalYear(mesStr){
  const p=(mesStr||'').slice(0,7).split('-');
  const yr=parseInt(p[0])||0, mo=parseInt(p[1])||0;
  return mo<=2?yr-1:yr;
}

// ── Boot ───────────────────────────────────────────────────────────────────────

async function init(){
  const saved=localStorage.getItem('pnl-theme')||'dark';
  document.documentElement.dataset.theme=saved;
  document.getElementById('theme-btn').textContent=saved==='light'?'☾ DARK':'☀ LIGHT';
  await loadInitialOptions();
}

init();
</script>
</body>
</html>$seed$, $seed$replicon$seed$, $seed$shared$seed$, NOW())
ON CONFLICT (name) DO NOTHING;

